INSERT INTO `characters` (`id`, `name`, `element`, `weapon`, `rarity`, `guide_content`, `image_url`, `mat_1`, `mat_2`, `mat_3_tier1`, `mat_3_tier2`, `mat_3_tier3`, `mat_3_tier4`, `hp_base`, `hp_max`, `atk_base`, `atk_max`, `def_base`, `def_max`, `rec_wp_1`, `rec_wp_2`, `rec_wp_3`, `rec_echo_1`, `rec_sonata_1`, `build_1_name`, `best_stat_1`, `best_stat_2`, `best_stat_3`, `best_stat_4`, `best_stat_5`, `skill_normal_name`, `skill_normal_desc`, `skill_resonance_name`, `skill_resonance_desc`, `skill_forte_name`, `skill_forte_desc`, `skill_liberation_name`, `skill_liberation_desc`, `skill_intro_name`, `skill_intro_desc`, `skill_outro_name`, `skill_outro_desc`, `skill_inherent1_name`, `skill_inherent1_desc`, `skill_inherent2_name`, `skill_inherent2_desc`, `skill_normal_icon`, `skill_resonance_icon`, `skill_forte_icon`, `skill_liberation_icon`, `skill_intro_icon`, `skill_outro_icon`, `skill_inherent1_icon`, `skill_inherent2_icon`, `rc1_name`, `rc1_desc`, `rc1_icon`, `rc2_name`, `rc2_desc`, `rc2_icon`, `rc3_name`, `rc3_desc`, `rc3_icon`, `rc4_name`, `rc4_desc`, `rc4_icon`, `rc5_name`, `rc5_desc`, `rc5_icon`, `rc6_name`, `rc6_desc`, `rc6_icon`, `team_mate_1`, `team_mate_2`, `team_mate_3`, `team_mate_4`, `team_icon_url`) VALUES
(23, 'Camellya', 'Havoc', 'Sword', 5, 'Camellya in Wuthering Waves is a 5 Stars Havoc character who wields a Sword as their weapon type.\r\n\r\nA Bloom Bearer of the Black Shores, Camellya is free-spirited and dangerously charming. She roams Solaris in search of talent, immersing herself in the present and relishing its pleasures, all while remaining true to herself, unburdened by thoughts of the past or future.', 'camellya.jpg', 'Topological Confinement', 'Nova', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 826, 10325, 36, 450, 95, 1161, 'Red Spring', 'Blazing Brilliance', 'Emerald of Genesis', 'Dreamless', 'Havoc Eclipse', '2 Set: Havoc DMG + 10%.\r\n\r\n5 Set: Havoc DMG + 7.5% after releasing Basic Attack or Heavy Attack. This effect stacks up to 4 times, each stack lasts 15s.', 'Crit. Rate | >70.0%', 'Crit. DMG | >240.0%', 'ATK | >2200', NULL, NULL, 'Burgeoning', 'Basic Attack\r\nPerform up to 5 consecutive attacks, dealing Havoc DMG. After performing Basic Attack Stage 3 or Heavy Attack Pruning, hold Normal Attack Button to continuously strike the target, dealing Havoc DMG. Basic Attack Stage 4 is automatically followed by Basic Attack Stage 5.\r\nHeavy Attack - Pruning\r\nConsume STA to attack the target, dealing Havoc DMG.\r\nMid-air Attack\r\nConsume STA to perform Plunging Attack, dealing Havoc DMG.\r\nDodge Counter\r\nUse Basic Attack right after a successful Dodge to attack the target, dealing Havoc DMG.', 'Valse of Bloom and Blight', 'Crimson Blossom\r\nAttack the target, dealing Havoc DMG (considered Basic Attack DMG), then enter Blossom Mode. This attack can be performed in mid-air.\r\nBlossom Mode\r\n- Unable to move while suspended on vines. - Basic Attack and Heavy Attack Pruning are replaced by Basic Attack Vining Waltz: chain together 4 consecutive attacks, dealing Havoc DMG, considered Basic Attack DMG. - When performing Vining Waltz Stage 3, hold Normal Attack Button to cast Blazing Waltz that deals Havoc DMG before automatically performing Vining Waltz Stage 4. - Dodge Counter is replaced by Dodge Counter Atonement. Tap Normal Attack Button right after a successful Dodge to attack the target, dealing Havoc DMG, considered Basic Attack DMG. - Resonance Skill is replaced by Resonance Skill Floral Ravage. Casting Floral Ravage deals Havoc DMG, considered Basic Attack DMG. - Resonance Skill Floral Ravage can be cast in mid-air. - Blossom Mode ends after casting Resonance Skill Floral Ravage. - Blossom Mode ends after using the Levitator. - Jump is replaced with Basic Attack Vining Ronde. Use Jump to attack the target at the cost of STA, dealing Havoc DMG (considered Basic Attack DMG). This ends the Blossom Mode. - Using Basic Attack Vining Waltz and Basic Attack Blazing Waltz in mid-air consumes STA. - Casting Resonance Skill Floral Ravage doesn\'t restore STA. - Consume STA continuously to stay suspended on the vines.', 'Vegetative Universe', 'Hitting a target with Normal Attack, Basic Attack Vining Waltz, Basic Attack Blazing Waltz, Basic Attack Vining Ronde, Dodge Counter Atonement , Resonance Skill Crimson Blossom, and Resonance Skill Floral Ravage consumes Crimson Pistils. The Energy Regen Multiplier of this attack is increased by 150%. Consuming 10 Crimson Pistils recovers 4 Concerto Energy and obtains 1 Crimson Bud(s). Each bud lasts for 15s, stacking up to 10 times.\r\nForte Circuit: Ephemeral\r\nWhen Concerto Energy is fully recovered, and Ephemeral is not on Cooldown, Resonance Skill is replaced with Ephemeral. Casting Ephemeral consumes 70 Concerto Energy and deals Havoc DMG to the targets. This damage is considered Basic Attack DMG. Camellya enters Budding Mode after casting Ephemeral. This can be cast in mid-air.\r\nBudding Mode\r\n- Sweet Dream: Increase the DMG Multiplier of Normal Attack, Basic Attack Vining Waltz, Basic Attack Blazing Waltz, Basic Attack Vining Ronde, Dodge Counter Atonement, Resonance Skill Crimson Blossom, and Resonance Skill Floral Ravage by 50%. - Casting Ephemeral consumes all Crimson Buds. Each Crimson Bud consumed additionally increases the DMG Multiplier of Sweet Dream by 5%, up to 50%. - When in Budding Mode, Camellya cannot gain Crimson Buds. - When in Budding Mode, the Energy Regen Multiplier of Normal Attack, Basic Attack Vining Waltz, Basic Attack Blazing Waltz, Basic Attack Vining Ronde, Dodge Counter Atonement, Resonance Skill Crimson Blossom, and Resonance Skill Floral Ravage is reduced to 0%. - Budding Mode ends when Camellya is switched off the field. - Budding Mode ends when all Crimson Pistils are consumed.\r\nCrimson Pistil\r\nCamellya can hold up to 100 Crimson Pistils. - Casting Intro Skill Everblooming recovers 100 Crimson Pistils. - Activating Forte Circuit\'s Ephemeral recovers 100 Crimson Pistils.', 'Fervor Efflorescent\r\n', 'Attack the target, dealing Havoc DMG. This attack can be performed in mid-air.', 'Everblooming', 'Attack the target, dealing Havoc DMG.', 'Twining', 'Attack the target, dealing Havoc DMG equal to 329.24% of Camellya\'s ATK. After activating Forte Circuit\'s Ephemeral, the next Outro Skill Twining deals additional Havoc DMG equal to 459.02% of Camellya\'s ATK.', 'Seedbed', 'Gain 15% Havoc DMG Bonus. DMG dealt by Heavy Attack Pruning is now considered Basic Attack DMG.', 'Epiphyte', 'Gain 15% Basic DMG Bonus. Gain increased resistance to interruption when casting Basic Attack, Basic Attack Vining Waltz, and Basic Attack Blazing Waltz.', 'camellya_normal.png', 'camellya_resonance.png', 'camellya_forte.png', 'camellya_liberation.png', 'camellya_intro.png', 'camellya_outro.png', 'camellya_inherent1.png', 'camellya_inherent2.png', 'Somewhere No One Travelled', 'Casting Intro Skill Everblooming increases Camellya\'s Crit. DMG by 28% for 18s. This effect can be triggered once every 25s. Immune to interruptions while casting Ephemeral.', 'Somewhere_No_One_Travelled.png', 'Calling Upon the Silent Rose', 'The DMG Multiplier of Resonance Skill Ephemeral is increased by 120%.', 'Calling_Upon_the_Silent_Rose.png', 'A Bud Adorned by Thorns', 'The DMG Multiplier of Resonance Liberation Fervor Efflorescent is increased by 50%. When in Budding Mode, Camellya\'s ATK is increased by 58%.\r\n', 'Sequence_Node_A_Bud_Adorned_by_Thorns.png', 'Roots Set Deep In Eternity', 'Casting Everblooming gives all team members 25% Basic Attack DMG Bonus for 30s.', 'Sequence_Node_Roots_Set_Deep_In_Eternity.png', 'Infinity Held in Your Palm', 'The DMG Multipliers of Intro Skill Everblooming is increased by 303% and Outro Skill Twining is increased by 68%.', 'Sequence_Node_Infinity_Held_in_Your_Palm.png', 'Bloom For You Thousand Times Over', 'The DMG Multiplier of Forte Circuit\'s Sweet Dream is additionally increased by 150%. Forte Circuit Perennial: Within 15s after casting Ephemeral, if Concerto Energy is full and Perennial is not on cooldown, Resonance Skill is replaced with Perennial. Casting Perennial consumes 50 Concerto Energy and recovers 50 Crimson Pistils, dealing Havoc DMG equal to 100% of Ephemeral DMG, considered Basic Attack DMG. This skill can be cast once every 25s. Camellya enters Budding Mode after casting Perennial and removes all Crimson Buds. The bonus DMG Multiplier granted by Forte Circuit\'s Sweet Dream is increased to 250%. Immune to interruptions when casting Perennial.', 'Sequence_Node_Bloom_For_You_Thousand_Times_Over.png', 46, 24, 47, 48, 'Resonator_Camellya.png'),
(24, 'Youhu', 'Glacio', 'Gauntlets', 4, 'Youhu in Wuthering Waves is a 4 Stars Glacio character who wields a Gauntlets as their weapon type.\r\n\r\nA voluble and whimsical antique appraiser. Known for creating limericks on the spot, she presents her appraisals with flair and precision. She sets up a stall on the street, ensuring antiques find their way to those who truly cherish them.', 'youhu.jpg', 'Topological Confinement', 'Violet Coral', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 798, 9975, 21, 262, 86, 1051, 'Abyss Surges', 'Celestial Spiral', 'Hollow Mirage', 'Bell-Borne Geochelone', 'Rejuvenating Glow', '• Healing Bonus + 10%.\r\n• Increases the ATK of all party members by 15% for 30s upon healing allies.', 'Crit. Rate | >60.0%', 'Crit. DMG | >220.0%', NULL, NULL, NULL, 'Frosty Punches', 'Basic Attack\r\nPerform up to 4 consecutive attacks, dealing Glacio DMG.\r\nHeavy Attack\r\n- When Frost is full, hold the Normal Attack Button to cast Frostfall. - When Frost is full during the Fortune Rolling state, release the Normal Attack Button to cast Frostfall. If Youhu cannot cast Frostfall at the moment, perform Lucky Draw once instead. Youhu can obtain Frost in the following ways: - When Frost is not full, hold Normal Attack Button to enter the Fortune Rolling state and restore Frost over time. - When Basic Attacks hit a target.\r\nHeavy Attack: Frostfall\r\nYouhu dashes forward, dealing Glacio DMG, and performs Lucky Draw once.\r\nMid-air Attack\r\nPerform a Plunging Attack at the cost of STA, dealing Glacio DMG.\r\nDodge Counter\r\nWhen Youhu possesses no Antique, quickly press Normal Attack Button right after a successful Dodge to thrust forward, dealing Glacio DMG, and perform Lucky Draw once.', 'Scroll Divination', 'Youhu smashes her scroll down at the enemy, dealing Glacio DMG, restoring HP for all party members nearby, and performs Lucky Draw once.\r\nLucky Draw\r\nYouhu obtains a random Antique after the Lucky Draw. With an Antique, her next Basic Attack will activate the corresponding Antique Appraisal. Only one Antique can exist at a time, and the newly drawn Antique will replace the existing one.\r\nAntique Appraisal\r\n- Chime: Attack the enemy with a Chime, dealing Glacio DMG. Chime can effectively reduce the enemy\'s Vibration Strength. - Ruyi: Batter the enemy with a Ruyi, dealing Glacio DMG. Ruyi has a higher DMG Multiplier. - Ding: Ram into the enemy on a Ding, dealing Glacio DMG. Ding can effectively break the enemy\'s stance. - Mask: Throw a Mask at enemies in front, dealing Glacio DMG. Mask can pull in enemies along its path.', 'Poetic Essence', 'At four Auspices, hold the Normal Attack button to release Poetic Essence, dealing Glacio DMG, considered as Resonance Skill DMG, while restoring HP for all nearby party members. Youhu can hold up to four Auspices.\r\nPoetic Essence\r\nDeal Glacio DMG to enemies within the range and additionally obtain one of the following effects based on the Auspice combination: - Free Verse: Four different types Auspices. Additionally reduce the Vibration Strength of hit enemies. - Antithesis: A pair of Auspices. Increase Poetic Essence\'s DMG by 70%. - Double Pun: Two pairs of Auspices. Additionally restore HP for all nearby party members. - Triplet: Three identical Auspices. Increase Poetic Essence\'s DMG by 175%. - Perfect Rhyme: Four identical Auspices. Simultaneously activate the effects of Free Verse, Double Pun, and Triplet. Casting Poetic Essence removes all Auspices.\r\nAuspice\r\n- Youhu gains an Auspice through Antique Appraisal. Use Basic Attack while holding an Antique to receive the corresponding Auspice. - Youhu unlocks Antiques by casting Resonance Skill Scroll Divination, Intro Skill Scroll of Wonders, Heavy Attack Frostfall, Resonance Liberation Fortune\'s Favor, and Dodge Counter.', 'Fortune\'s Favor', 'Youhu hurls her scroll at the enemy, causing a Glacio DMG blast in the area. On the blast, four buttons will appear. Choose a button within the specified time to obtain the corresponding Antique. Otherwise, obtain one random Antique.', 'Scroll of Wonders', 'Toss out the scroll and perform Lucky Draw once.', 'Timeless Classics', 'The incoming Resonator has their Coordinated Attack DMG Amplified by 100% for 28s.', 'Treasured Piece', 'Restore HP for all nearby party members based on 30% of the healing provided by Resonance Skill Scroll Divination when Resonance Skill Antique Appraisal is cast.', 'Rare Find', 'Gain 15% Glacio DMG Bonus for 14s upon casting Intro Skill Scroll of Wonders.', 'Skill_Gauntlets.png', 'Skill_Scroll_Divination.png', 'Skill_Poetic_Essence.png', 'Skill_Fortune_Favor.png', 'Skill_Scroll_of_Wonders.png', 'Skill_Timeless_Classics.png', 'Skill_Treasured_Piece.png', 'Skill_Rare_Find.png', 'Waterside Respite', 'Youhu has a 10% chance to gain immunity to damage and interruption after casting Lucky Draw. This effect lasts for 5s or until she is switched out.', 'Sequence_Node_Waterside_Respite.png', 'Sunroom Siesta', 'The DMG bonus of Antithesis, Triplet and Perfect Rhyme on Poetic Essence is doubled.', 'Sequence_Node_Sunroom_Siesta.png', 'Restless Sleep', 'Youhu\'s ATK is increased by 20%.', 'Sequence_Node_Restless_Sleep.png', 'Frosted Lullaby', 'Every time Resonance Skill Scroll Divination is cast, there is a 20% chance that the skill will not enter Cooldown.', 'Sequence_Node_Frosted_Lullaby.png', 'Dreamland Meander', 'When Intro Skill Scroll of Wonders is cast, Youhu\'s Crit. Rate is increased by 15% for 14s.', 'Sequence_Node_Dreamland_Meander.png', 'Slumber Evermore', 'When casting Resonance Skill Antique Appraisal, gain 1 stack of Sky Blue, stackable up to 4 times, lasting for 7s. Each stack increases Youhu\'s Crit. DMG by 15%.', 'Sequence_Node_Slumber_Evermore.png', 30, 27, 25, 39, 'Resonator_Youhu.png'),
(25, 'Shorekeeper', 'Spectro', 'Rectifier', 5, 'Shorekeeper in Wuthering Waves is a 5 Stars Spectro character who wields a Rectifier as their weapon type.\r\n\r\nThe Shorekeeper, guardian of the Black Shores—this title alone once defined her. But desires, bonds, and emotions… She only began to understand these things after meeting you.', 'shorekeeper.jpg', 'Topological Confinement', 'Nova', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 1337, 16712, 23, 287, 90, 1099, 'Stellar Symphony', 'Variation', 'Rectifier#25', 'Fallacy of No Return', 'Rejuvenating Glow', '• Healing Bonus + 10%.\r\n• Increases the ATK of all party members by 15% for 30s upon healing allies.', 'Energy Regen | >230%', 'Crit. DMG | >190.0%', NULL, NULL, NULL, 'Origin Calculus', 'Basic Attack\r\nPerform up to 4 consecutive attacks, dealing Spectro DMG. Each hit generates 1 Collapsed Core.\r\nHeavy Attack\r\nHold the Normal Attack Button to enter Unbound Form, which consumes STA continuously. While in this form, Shorekeeper will: - Generate a segment of Deductive Data every second; - Automatically collect nearby plant collectibles. Using up all STA or actions such as casting Basic Attack will end the Unbound Form and deal Spectro DMG to the target. Each accumulated segment of Deductive Data will convert into a segment of Empirical Data and generate a Collapsed Core.\r\nMid-air Attack\r\nConsume STA to perform a Plunging Attack. Each hit generates 1 Collapsed Core. Quickly Press the Normal Attack Button after the Plunging Attack to perform Basic Attack Stage 2.\r\nDodge Counter\r\nPress the Normal Attack Button after a successful Dodge to attack a target, dealing Spectro DMG.', 'Chaos Theory', 'Restore HP for all nearby party members and summon 5 Dim Star Butterflies, which automatically track and attack a target, dealing Spectro DMG. Follow up with Basic Attack in time to start the Basic Attack cycle from Stage 2. Can be performed in mid-air.\r\n\r\n', 'Astral Chord', 'Flare Star Butterfly\r\nHitting a target with a Normal Attack generates a Collapsed Core, which transforms into a Flare Star Butterfly after 6s. Flare Star Butterflies automatically track and attack a target, dealing Spectro DMG. If there are already 5 Collapsed Cores, Shorekeeper\'s next Basic Attack hit will instantly convert a Collapsed Core into a Flare Star Butterfly.\r\nIllation\r\nWhen Shorekeeper has 5 segments of Empirical Data, casting Heavy Attack will consume all segments to pull in nearby targets, dealing Spectro DMG. Meanwhile, all generated Collapsed Cores will instantly transform into Flare Star Butterflies.\r\nTransmutation\r\nWhen Shorekeeper has 5 segments of Empirical Data, casting Mid-air Attack will consume all segments to deal Spectro DMG. Meanwhile, all generated Collapsed Cores will instantly transform into Flare Star Butterflies. Quickly press the Normal Attack Button afterward to perform Basic Attack Stage 2.\r\nEmpirical Data\r\nShorekeeper can hold up to 5 segments of Empirical Data. - Obtain 1 segment of Empirical Data when Basic Attack Stage 1, 2, or 4 hits a target. - Obtain 2 segments of Empirical Data when Basic Attack Stage 3 hits a target. - Obtain 1 segment of Empirical Data when Mid-air Attack hits a target. - Obtain 1 segment of Empirical Data when Dodge Counter hits a target.\r\n\r\n', 'End Loop', 'Outer Stellarealm\r\nGenerate the Outer Stellarealm to restore HP for all party members within its effective range continuously. This effect can be triggered once every 3s.\r\nInner Stellarealm\r\nWhen a party member uses Intro Skill within the Outer Stellarealm, it evolves into the Inner Stellarealm. Within the effective range of the Inner Stellarealm, for every 0.2% of Shorekeeper\'s Energy Regen, all party members gain a 0.01% increase of Crit. Rate, up to 12.5%. Inner Stellarealm has all the effects of the Outer Stellarealm.\r\nSupernal Stellarealm\r\nWhen a party member uses Intro Skill within the Inner Stellarealm, it evolves into the Supernal Stellarealm. Within the effective range of the Supernal Stellarealm, for every 0.1% of Shorekeeper\'s Energy Regen, all party members gain a 0.01% increase of Crit. DMG, up to 25%. Supernal Stellarealm has all the effects of the Inner Stellarealm.', 'Proof of Existence', 'Enlightenment\r\nShorekeeper appears to restore HP for all nearby party members and summon 5 Dim Star Butterflies, which automatically track and attack a target, dealing Spectro DMG. This is considered Resonance Skill DMG.\r\nDiscernment\r\nWhen a Supernal Stellarealm is generated, Shorekeeper\'s first Intro Skill triggered in its duration will be replaced with Intro Skill Discernment. Casting Discernment ends the current Stellarealm, restores HP for all nearby party members, and deals Spectro DMG to the targets. This attack is guaranteed to be a Critical Hit dealing Resonance Liberation DMG. The Intro Skill Discernment can only be triggered once each time a Supernal Stellarealm is generated.', 'Binary Butterfly', 'Shorekeeper summons 1 Flare Star Butterfly and 1 Dim Star Butterfly to circle the Resonator on the field for up to 30s, granting the following effects: - If the Resonator on the field is hit or launched, tapping the Dodge Button allows the Resonator to immediately recover from the interruption, triggering a successful Dodge. The Resonator launched in the air can land on the ground standing if they are close to the ground. This effect can be triggered up to 5 time(s). - All nearby party members\' DMG is Amplified by 15%.', 'Life Entwined', 'When a Resonator other than Shorekeeper takes a fatal blow, they will not be knocked out and will instead be healed for 50% of Shorekeeper\'s HP while Shorekeeper loses the same amount of HP. Shorekeeper\'s HP will not go below 1 from this effect. This effect can be triggered once every 10 minutes.', 'Self Gravitation', 'When the on-field Resonator is within range of a Stellarealm, Shorekeeper\'s Energy Regen is increased by 10%, and Rover\'s Energy Regen is also increased by 10% if Rover is on the team.', 'Skill_Rectifier.png', 'Skill_Chaos_Theory.png', 'Skill_Astral_Chord.png', 'Skill_End_Loop.png', 'Skill_Proof_of_Existence.png', 'Skill_Binary_Butterfly.png', 'Skill_Life_Entwined.png', 'Skill_Self_Gravitation.png', 'Unspoken Conjecture', 'The Stellarealms generated by Resonance Liberation End Loop gain the following enhancements: - The effective range of the healing and buffs is extended by 150% - The duration is extended by 10s. - Casting Intro Skill Discernment no longer ends the existing Stellarealm.', 'Sequence_Node_Unspoken_Conjecture.png', 'Night\'s Gift and Refusal', 'The Outer Stellarealm now increases the ATK of all nearby party members by 40%.', 'Sequence_Node_Night_Gift_and_Refusal.png', 'Infinity Awaits Me', 'Casting Resonance Liberation End Loop grants Shorekeeper 20 Concerto Energy. This effect can be triggered once every 25s.', 'Sequence_Node_Infinity_Awaits_Me.png', 'Overflowing Quietude', 'Gain 70% additional Healing Bonus when casting Resonance Skill Chaos Theory.', 'Sequence_Node_Overflowing_Quietude.png', 'Echoes in Silence', 'Extend the ranges of the pulling effect of Basic Attack Stage 3 by 50% and Illation by 30%.', 'Sequence_Node_Echoes_in_Silence.png', 'To the New World', 'Increase the DMG Multiplier of Intro Skill Discernment by 42%. Casting Intro Skill Discernment increases Shorekeeper\'s Crit. DMG by 500%.', 'Sequence_Node_To_the_New_World.png', 28, 29, 27, 23, 'Resonator_Shorekeeper.png'),
(26, 'Xiangli Yao', 'Electro', 'Gauntlets', 5, 'Xiangli Yao in Wuthering Waves is a 5 Stars Electro character who wields a Gauntlets as their weapon type.\r\n\r\nPrincipal Investigator at Jinzhou Huaxu Academy, and the Academy\'s youngest multi-disciplinary scientist. A gentle soul with a sharp mind, whose relentless passion for Automata Mechanics always translates into constructive findings and insights.', 'xiangliyao.jpg', 'Hidden Thunder Tacet Core', 'Violet Coral', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 850, 10625, 34, 425, 100, 1222, 'Verity\'s Handle', 'Stonard', 'Abyss Surges', 'Tempest Mephis', 'Void Thunder', '• Electro DMG + 10%.\r\n• Electro DMG + 15% after releasing Heavy Attack or Resonance Skill. This effect stacks up to 2 times, each stack lasts 15s.', 'Crit. Rate | >65.0%', 'Crit. DMG | >270.0%', 'Energy Regen | >120.0%', NULL, NULL, 'Probe', 'Basic Attack\r\nPerform up to 5 consecutive attacks, dealing Electro DMG.\r\nHeavy Attack\r\nPerform a charged attack at the cost of STA, dealing Electro DMG.\r\nMid-air Attack\r\nPerform a Plunging Attack from mid-air at the cost of STA, dealing Electro DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Electro DMG.', 'Deduction', 'Attack the target, dealing Electro DMG.', 'Forever Seeking', 'Resonance Skill - Decipher\r\nWhen Capacity reaches 100, Resonance Skill Deduction is replaced by Resonance Skill Decipher. Consume 100 Capacity to cast Resonance Skill Decipher, dealing Electro DMG, considered as Resonance Liberation DMG.\r\nResonance Skill - Law of Reigns\r\nWhen Performance Capacity reaches 5 in Intuition state, Resonance Skill Divergence is replaced by Resonance Skill Law of Reigns. Consume 5 Performance Capacity to cast Resonance Skill Law of Reigns, dealing Electro DMG, considered as Resonance Liberation DMG.\r\nMid-air Attack - Revamp\r\nShortly after casting Resonance Skill Decipher or Resonance Skill Divergence, use Basic Attack to perform Mid-air Attack Revamp at the cost of STA, dealing Electro DMG, considered as Resonance Liberation DMG.\r\nCapacity\r\nXiangli Yao can hold up to 100 Capacity. Every Normal Attack Probe on hit grants Capacity. Every Resonance Skill Deduction on hit grants Capacity.\r\nPerformance Capacity\r\nXiangli Yao can hold up to 5 Performance Capacity. When in Intuition triggered by Resonance Liberation: Obtain 1 Performance Capacity when Stage 1 of Basic Attack Pivot - Impale hits a target. Obtain 2 Performance Capacity when Stage 2 or 3 of Basic Attack Pivot - Impale hits a target. Obtain 2 Performance Capacity for every Resonance Skill Divergence on hit. Obtain 3 Performance Capacity for every Mid-air Attack Revamp on hit. Obtain 2 Performance Capacity for every Dodge Counter Unfathomed on hit.', 'Cogitation Model', 'Attack the target, dealing Electro DMG. Enter Intuition. When in Intuition: -Obtain 3 Hypercube(s). Each time Resonance Skill Law of Reigns is cast, consume 1 Hypercube(s). Intuition ends once all Hypercubes are consumed. -Basic Attack and Heavy Attack are replaced with Basic Attack Pivot - Impale, which performs up to 3 consecutive attacks, dealing Electro DMG. -Resonance Skill Deduction is replaced with Resonance Skill Divergence, which deals Electro DMG. -Dodge Counter is replaced with Dodge Counter Unfathomed, considered as Resonance Liberation DMG.', 'Principle', 'Attack the target, dealing Electro DMG.', 'Chain Rule', 'Xiangli Yao will call down a laser beam upon the first target the incoming Resonator\'s Basic Attack hits, dealing Electro DMG equal to 237.63% of Xiangli Yao\'s ATK to an area. This effect lasts for 8s and can be triggered once every 2s, up to 3 times.', 'Knowing', 'Gain 5% Electro DMG Bonus after casting Resonance Skill for 8s, stackable for up to 4 times.', 'Focus', 'When in Intuition triggered by Resonance Liberation, Xiangli Yao\'s resistance to interruption is enhanced.', 'Skill_Gauntlets.png', 'Skill_Deduction.png', 'Skill_Forever_Seeking.png', 'Skill_Cogitation_Model.png', 'Skill_Principle.png', 'Skill_Chain_Rule.png', 'Skill_Knowing.png', 'Skill_Focus.png', 'Prodigy of Protégés', 'Resonance Skill Law of Reigns additionally launches 6 Convolution Matrices at enemies, each dealing Resonance Liberation DMG equal to 8% of the skill\'s DMG Multiplier.', 'Sequence_Node_Prodigy_of_Prot3Fs.png', 'Traces of Predecessors', 'Casting Resonance Skill or Resonance Liberation Cogitation Model increases Crit. DMG by 30% for 8s.', 'Sequence_Node_Traces_of_Predecessors.png', 'Ruins of Ancient', 'Casting Resonance Liberation Cogitation Model increases the DMG of the following Resonance Skill moves by 63% for 24s: Decipher, Deduction, Divergence, and Law of Reigns. This effect can be triggered up to 5 times.', 'Sequence_Node_Ruins_of_Ancient.png', 'Vessel of Rebirth', 'Casting Resonance Liberation Cogitation Model grants a 25% DMG Bonus to all team members\' Resonance Liberation for 30s.', 'Sequence_Node_Vessel_of_Rebirth.png', 'End of Stars', 'The DMG Multiplier of Outro Skill Chain Rule is increased by 222%. The DMG Multiplier of Resonance Liberation Cogitation Model is increased by 100%.', 'Sequence_Node_End_of_Stars.png', 'Solace of the Ordinary', 'The Hypercubes obtained from Resonance Liberation Cogitation Model are enhanced, increasing the DMG Multiplier of Resonance Skill Law of Reigns by 76%.', 'Sequence_Node_Solace_of_the_Ordinary.png', 30, 45, 25, 39, 'Resonator_Xiangli_Yao.png'),
(27, 'Zhezhi', 'Glacio', 'Rectifier', 5, 'Zhezhi in Wuthering Waves is a 5 Stars Glacio character who wields a Rectifier as their weapon type.\r\n\r\nAn artist for hire trying to make a living. Reserved and timid, she is not good with words but speaks volumes through her art, where her creations come to life with impossible authenticity.', 'zhezhi.jpg', 'Sound-Keeping Tacet Core', 'Lanternberry', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 980, 12250, 30, 375, 98, 1197, 'Rime-Draped Sprouts', 'Stringmaster', 'Cosmic Ripples', 'Impermanence Heron', 'Moonlit Clouds', '• Glacio DMG + 10%.\r\n• Glacio DMG + 10% after releasing Basic Attack or Heavy Attack. This effect stacks up to 3 times, each stack lasts 15s.', 'Crit. Rate | >65.0%', 'Crit. DMG | >260.0%', 'Energy Regen | >140.0%', NULL, NULL, 'Dimming Brush', 'Basic Attack\r\nPerform up to 3 consecutive attacks, dealing Glacio DMG.\r\nHeavy Attack\r\nConsume STA to perform an attack, dealing Glacio DMG. Heavy Attack does not reset the Basic Attack cycle.\r\nMid-air Attack\r\nConsume STA to perform up to 2 consecutive attacks while in mid-air, dealing Glacio DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Glacio DMG.', 'ManifestationDeal Glacio DMG. If Afflatus is no less than 60, consume 60 Afflatus to summon Phatasmi', 'Deal Glacio DMG. If Afflatus is no less than 60, consume 60 Afflatus to summon Phatasmic Imprint - Left and Phantasmic Imprint - Right. -Press the button on the ground to summon the Phantasmic Imprints on the ground. -Hold the button on the ground or press the button in mid-air to summon the Phantasmic Imprints in mid-air.', 'Ink and Wash', 'Phantasmic Imprint\r\nZhezhi may summon Phantasmic Imprints at the cost of Afflatus when casting Resonance Skill Manifestation or Heavy Attack Conjuration. Up to 1 of each of Phantasmic Imprint - Left, Phantasmic Imprint - Middle, and Phantasmic Imprint - Right can exist at the same time, each lasting for 15s.\r\nHeavy Attack - Conjuration\r\nThe 5 moves below consume STA to perform Conjuration to attack the target, dealing Glacio DMG. -Hold the Normal Attack button shortly after Basic Attack Stage 3. -Press the Normal Attack button shortly after casting Resonance Skill Manifestation. -Hold the Normal Attack button shortly after casting Resonance Skill Stroke of Genius or Resonance Skill Creation\'s Zenith. -Hold the Normal Attack button while in mid-air. -Hold the Normal Attack button after a successful Dodge. If Zhezhi has at least 30 Afflatus when performing any of these, consume 30 Afflatus to summon a Phantasmic Imprint - Middle.\r\nResonance Skill - Stroke of Genius\r\nWhen a Phatasmic Imprint is nearby, the Resonance Skill is replaced with Stroke of Genius, which can be cast while in mid-air. When it is cast, Zhezhi will: -Move to the location of the Phatasmic Imprint, remove it, and then summon an Ivory Herald to attack the target, dealing Glacio DMG, considered as Basic Attack DMG. Refresh the mid-air Dodge attempts if the target Phatasmic Imprint is in mid-air. -Gain 1 stack of Painter\'s Delight, lasting for 8s and stacking up to 2 times.\r\nResonance Skill - Creation\'s Zenith\r\nWhen a Phantasmic Imprint is nearby and there are 2 stacks of Painter\'s Delight, Stroke of Genius is replaced with Creation\'s Zenith, which can be cast while in mid-air. When it is cast, Zhezhi will: -Lose all stacks of Painter\'s Delight -Move to the location of the Phantasmic Imprint, remove it, and then summon an Ivory Herald to attack the target, dealing greater Glacio DMG, considered as Basic Attack DMG, additionally increasing the Basic Attack DMG Bonus by 18% for 27s. Refresh the mid-air Dodge attempts if the target Phatasmic Imprint is in mid-air.\r\nAfflatus\r\nZhezhi can hold up to 90 Afflatus. Normal Attacks grant Afflatus on hit. Casting Intro Skill grants Afflatus.', 'Living Canvas', 'Summon Inklit Spirits for assistance. Can be cast in mid-air.\r\nInklit Spirit\r\nWhen the active Resonator deals DMG, an Inklit Spirit will be summoned to perform a Coordinated Attack, dealing Glacio DMG, considered as Basic Attack DMG. -For 3s after dealing DMG, 1 Inklit Spirit is summoned per second. This effect can trigger once per second. Damage dealt by an Inklit Spirit does not trigger this effect. -Up to 1 Inklit Spirit can be summoned every second, and up to 21 in total. -This effect lasts for 30s, or until max Inklit Spirits are summoned.', 'Radiant Ruin', 'Attack the target, dealing Glacio DMG.', 'Carve and Draw', 'The incoming Resonator has their Glacio DMG Amplified by 20% and Resonance Skill DMG Amplified by 25% for 14s or until they are switched out.', 'Calligrapher\'s Touch', 'When casting Resonance Skill Stroke of Genius or Resonance Skill Creation\'s Zenith, ATK is increased by 6% for 27s. This can be stacked up to 3 time(s).', 'Flourish', 'After Outro Skill is cast, restore 15 Resonance Energy for the incoming Resonator.', 'Skill_Rectifier.png', 'Skill_Manifestation.png', 'Skill_Ink_and_Wash.png', 'Skill_Living_Canvas.png', 'Skill_Radiant_Ruin.png', 'Skill_Carve_and_Draw.png', 'Skill_Calligrapher_Touch.png', 'Skill_Flourish.png', 'Brushwork\'s Finish', 'Casting Resonance Skill Creation\'s Zenith restores 15 Resonance Energy and increases Crit. Rate by 10% for 27s.', 'Sequence_Node_Brushwork_Finish.png', 'Vivid Strokes', 'Max Inklit Spirits summoned by Resonance Liberation Living Canvas increases by 6.', 'Sequence_Node_Vivid_Strokes.png', 'Reflection\'s Grace', 'Casting Resonance Skill Manifestation, Resonance Skill Stroke of Genius, or Resonance Skill Creation\'s Zenith increases ATK by 15% for 27s, stacking up to 3 time(s).', 'Sequence_Node_Reflection_Grace.png', 'Hue\'s Spectrum', 'Casting Resonance Liberation Living Canvas increases ATK of Resonators on the team 20% for 30s.', 'Sequence_Node_Hue_Spectrum.png', 'Composition\'s Clue', 'For every 3 Inklit Spirits summoned by Resonance Liberation Living Canvas, 1 extra Inklit Spirit is summoned to perform a Coordinated Attack, dealing DMG equal to 140% of Inklit Spirit\'s DMG, considered as Basic Attack DMG. This damage dealt will not further summon Inklit Spirit.', 'Sequence_Node_Composition_Clue.png', 'Infinite Legacy', 'Casting Resonance Skill Stroke of Genius or Resonance Skill Creation\'s Zenith summons an extra Ivory Herald to deal DMG equal to 120% of Resonance Skill Stroke of Genius\'s DMG, considered as Basic Attack DMG.', 'Sequence_Node_Infinite_Legacy.png', 29, 45, 25, 39, 'Resonator_Zhezhi.png'),
(28, 'Changli', 'Fusion', 'Sword', 5, 'Changli in Wuthering Waves is a 5 Stars Fusion character who wields a Sword as their weapon type.\r\n\r\nChangli is a counselor serving the Jinzhou Magistrate, and former Secretary-General in the capital. Shrouded in flames, she\'s fated to burn brightly until her final embers. With her fiery determination and strategic mindset, she rises to power, always thinking ahead to reach her ultimate goal.', 'changli.jpg', 'Rage Tacet Core', 'Pavo Plum', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 831, 10387, 37, 462, 90, 1099, 'Blazing Brilliance', 'Emerald of Genesis', 'Red Spring', 'Inferno Rider', 'Molten Rift', '• Fusion DMG + 10%.\r\n• Fusion DMG + 30% for 15s after releasing Resonance Skill.', 'Crit. Rate | >70.0%', 'Crit. DMG | >270.0%', 'ATK | >2200', NULL, NULL, 'Blazing Enlightment', 'Basic Attack\r\nPerform up to 4 consecutive attacks, dealing Fusion DMG. After releasing Basic Attack 4, enter True Sight, lasting for 12s.\r\nMid-air Attack\r\nConsume Stamina to perform up to 4 consecutive attacks in mid-air, dealing Fusion DMG. After releasing Mid-air Attack 4, enter True Sight, lasting for 12s.\r\nHeavy Attack\r\nHold Basic Attack on the ground to perform an upward strike at the cost of Stamina, dealing Fusion DMG. Use Basic Attack within a certain time to release Mid-Air Attack 3.\r\nMid-air Heavy Attack\r\nShortly after holding Basic Attack in mid-air or using Basic Attack True Sight: Charge, use Basic Attack to perform a plunging attack at the cost of Stamina, dealing Fusion DMG. Use Basic Attack within a certain time to release Basic Attack 3.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Fusion DMG.', 'Tripartite Flames', 'True Sight: Capture\r\nAfter releasing Resonance Skill, Changli dashes towards the enemy and enters True Sight, lasting for 12s. In the end, she releases a plunging attack, dealing Fusion DMG. True Sight: Capture has 2 initial charges and holds up to 2 charges at maximum. The number of charges is replenished by 1 every 12s. Can be cast in mid-air.\r\nBasic Attack: True Sight - Conquest\r\nWhen in True Sight, if Changli uses Ground Basic Attack, she releases True Sight: Conquest, dashing towards the enemy and dealing Fusion DMG, considered as Resonance Skill DMG. After releasing True Sight: Conquest, True Sight ends.\r\nBasic Attack: True Sight - Charge\r\nWhen in True Sight, if Changli jumps or uses Basic Attack in mid-air, she releases True Sight: Charge, dashing towards the enemy and dealing Fusion DMG, considered as Resonance Skill DMG. After releasing True Sight: Charge, True Sight ends.', 'Flaming Sacrifice', 'Heavy Attack: Flaming Sacrifice\r\nWhen releasing Heavy Attack, if Changli carries 4 stacks of Enflamement, she consumes all stacks of Enflamement to cast Flaming Sacrifice, dealing Fusion DMG, considered as Resonance Skill DMG. While casting Flaming Sacrifice, Changli takes 40% less DMG.\r\nEnflamement\r\nChangli can hold up to 4 stacks of Enflamement. Changli obtains 1 stack of Enflamement for every Basic Attack: True Sight - Conquest on hit. Changli obtains 1 stack of Enflamement for every Basic Attack: True Sight - Charge on hit. Changli obtains 4 stacks of Enflamement for every Resonance Liberation Radiance of Fealty.', 'Radiance of Fealty', 'Deal Fusion DMG to nearby targets, obtaining 4 stacks of Enflamement, and entering Fiery Feather. Can be cast in mid-air.\r\nFiery Feather\r\nWhen Changli releases Heavy Attack Flaming Sacrifice within 10s, her ATK is increased by 25%, after which Fiery Feather ends.', 'Loong\'s Halo', 'Attack the target, dealing Spectro DMG.', 'Temporal Bender', 'Summoning the power homologous with the Sentinel, Jinhsi may now gain Incandescence via Eras in Unity from damage of the same Attribute more effectively, at 1 time(s) every 1s for 20s.', 'Radiant Surge', 'Jinhsi gains 20% Spectro DMG Bonus.', 'Converged Flash', 'DMG Multiplier of Intro Skill Loong\'s Halo is increased by 50%.', 'Skill_Blazing_Enlightenment.png', 'Skill_Tripartite_Flames.png', 'Skill_Flaming_Sacrifice.png', 'Skill_Radiance_of_Fealty.png', 'Skill_Obedience_of_Rules.png', 'Skill_Strategy_of_Duality.png', 'Skill_Secret_Strategist.png', 'Skill_Sweeping_Force.png', 'Abyssal Ascension', 'When casting Basic Attack \"Incarnation - Basic Attack\" or Resonance Skill Crescent Divinity, Jinhsi gains one stack of Herald of Revival, stacking up to 4 times and lasting for 6s. When casting Resonance Skill Illuminous Epiphany, Jinhsi consumes all stacks of Herald of Revival. Each stack increases the damage of Resonance Skill Illuminous Epiphany by 20%.', 'Sequence_Node_Hidden_Thoughts.png', 'Chronofrost Repose', 'Jinhsi restores 50 Incandescence while staying out of combat for more than 4s. This effect can only be triggered 1 time(s) every 4s.', 'Sequence_Node_Pursuit_of_Desires.png', 'Celestial Incarnate', 'Jinhsi gains one stack of Immortal\'s Descendancy after casting Intro Skill Loong\'s Halo. Each stack of Immortal\'s Descendancy increases Jinhsi\'s ATK by 25%, stacking up to 2 time(s) and lasting for 20s.', 'Sequence_Node_Learned_Secrets.png', 'Benevolent Grace', 'When Jinhsi casts Resonance Liberation Purge of Light or Resonance Skill Illuminous Epiphany, all nearby Resonators on the team gain 20% Attribute DMG Bonus for 20s.', 'Sequence_Node_Polished_Words.png', 'Frostfire Illumination', 'The DMG Multiplier of Resonance Liberation Purge of Light is increased by 120%.', 'Sequence_Node_Sacrificed_Gains.png', 'Thawing Triumph', 'The DMG Multiplier of Resonance Skill Illuminous Epiphany is increased by 45% and the additional DMG Multiplier gained by consuming Incandescence is increased by 45%.', 'Sequence_Node_Realized_Plans.png', 27, 29, 25, 39, 'Resonator_Changli.png'),
(29, 'Jinhsi', 'Spectro', 'Broadblade', 5, 'Jinhsi in Wuthering Waves is a 5 Stars Spectro character who wields a Broadblade as their weapon type.\r\n\r\nJinhsi, Magistrate of Jinzhou, gently brightens the hopes of her people, like rays of winter sunlight. As the revered Sentinel\'s Appointed Resonator, she displays humility and wholeheartedly commits herself to guiding her people towards a brilliant future.', 'jinhsi.jpg', 'Elegy Tacet Core', 'Loong\'s Pearl', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 866, 10825, 33, 412, 103, 1258, 'Ages of Harvest', 'Lustrous Razor', 'Autumntrace', 'Jué', 'Celestial Light', '• Spectro DMG + 10%.\r\n• Spectro DMG + 30% for 15s after releasing Intro Skill.', 'Crit. Rate | >70.0%', 'Crit. DMG | >275.0%', 'Resonance Skill DMG Bonus | >20.0%', NULL, NULL, 'Slash of Breaking Dawn\r\n', 'Basic Attack\r\nPerform up to 4 consecutive strikes, dealing Spectro DMG.\r\nHeavy Attack\r\nPerform a charged attack at the cost of STA, dealing Spectro DMG.\r\nMid-air Attack\r\nPerform a Plunging Attack while in mid-air at the cost of STA, dealing Spectro DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to counterattack, dealing Spectro DMG.', 'Trailing Lights of Eons', 'Dash forward and perform consecutive strikes that inflict Spectro DMG.\r\nOverflowing Radiance\r\nAfter Jinhsi uses Basic Attack 4 or, while not in Incarnation, Intro Skill Loong\'s Halo, an alternative Resonance Skill Overflowing Radiance is available within 5s. Resonance Skill Overflowing Radiance inflicts Spectro DMG and sends Jinhsi into Incarnation. Can be cast in mid-air.', 'Luminal Synthesis', 'Incarnation\r\nWhile in Incarnation: - Alternative Basic Attack \"Incarnation - Basic Attack\" becomes available. Perform up to 4 consecutive strikes, dealing Spectro DMG considered as Resonance Skill DMG. The basic attack cycle of this will not be reset. Can be cast in mid-air. - Alternative Resonance Skill \"Crescent Divinity\" becomes available. Deal Spectro DMG. Can be cast in mid-air. - Alternative Heavy Attack \"Incarnation - Heavy Attack\" becomes available. Attack the target in mid-air at the cost of Stamina, dealing Spectro DMG. - Alternative Dodge \"Incarnation - Dodge\" is available while in mid-air. Can be cast multiple times at the cost of Stamina. - Alternative Dodge Counter \"Incarnation - Dodge Counter\" becomes available. Deal Spectro DMG. Can be cast in mid-air.\r\nResonance Skill - Illuminous Epiphany\r\nAfter Stage 4 of Incarnation - Basic Attack, Incarnation terminates and Jinhsi gains Ordination Glow. Can be cast in mid-air. While Ordination Glow lasts: - Basic Attack is replaced with Heavy Attack \"Incarnation - Heavy Attack\". Attack the target in mid-air at the cost of Stamina, dealing Spectro DMG. - Resonance Skill is replaced with Resonance Skill \"Illuminous Epiphany\". Send out Solar Flare that detonates as Stella Glamor, dealing Spectro DMG after a short delay. Consume up to 50 Incandescence, with each point of Incandescence granting bonus DMG Multiplier percentage to Stella Glamor. Can be cast in mid-air. - After casting Resonance Skill Illuminous Epiphany, Jinhsi gains Unison. This can be triggered once every 25s.\r\nUnison\r\nWhile Jinhsi has Unison, switching to other Resonators will remove Jinhsi\'s Unison to trigger Jinhsi\'s Outro Skill and the incoming Resonator\'s Intro Skill. Unison will be consumed in priority in place of Concerto Energy when Concerto Energy is full.\r\nIncandescence\r\nJinhsi can hold up to 50 Incandescence. When Jinhsi is in the party, all nearby Resonators in the party gain Eras in Unity. Eras in Unity provides 2 independent effects: Jinhsi gains 1 Incandescence anytime Resonators in the party inflict Attribute DMG. This effect may be triggered by damage of the same Attribute for up to 1 time(s) every 3s. Additionally, Jinhsi gains 2 Incandescence when Resonators in the party damage the enemy with Coordinated Attacks. This effect may be triggered by Coordinated Attacks of the same Attribute for up to 1 time(s) every 3s.', 'Purge of Light', 'Unleash the power of invocation to deal Spectro DMG. Can be cast in mid-air.', 'Loong\'s Halo', 'Attack the target, dealing Spectro DMG.', 'Temporal Bender', 'Summoning the power homologous with the Sentinel, Jinhsi may now gain Incandescence via Eras in Unity from damage of the same Attribute more effectively, at 1 time(s) every 1s for 20s.', 'Radiant Surge', 'Jinhsi gains 20% Spectro DMG Bonus.', 'Converged Flash', 'DMG Multiplier of Intro Skill Loong\'s Halo is increased by 50%.', 'Skill_Broadblade.png', 'Skill_Trailing_Lights_of_Eons.png', 'Skill_Luminal_Synthesis.png', 'Skill_Purge_of_Light.png', 'Skill_Loong27s_Halo.png', 'Skill_Temporal_Bender.png', 'Skill_Radiant_Surge.png', 'Skill_Converged_Flash.png', 'Abyssal Ascension', 'When casting Basic Attack \"Incarnation - Basic Attack\" or Resonance Skill Crescent Divinity, Jinhsi gains one stack of Herald of Revival, stacking up to 4 times and lasting for 6s. When casting Resonance Skill Illuminous Epiphany, Jinhsi consumes all stacks of Herald of Revival. Each stack increases the damage of Resonance Skill Illuminous Epiphany by 20%.', 'Sequence_Node_Abyssal_Ascension.png', 'Chronofrost Repose', 'Jinhsi restores 50 Incandescence while staying out of combat for more than 4s. This effect can only be triggered 1 time(s) every 4s.', 'Sequence_Node_Chronofrost_Repose.png', 'Celestial Incarnate', 'Jinhsi gains one stack of Immortal\'s Descendancy after casting Intro Skill Loong\'s Halo. Each stack of Immortal\'s Descendancy increases Jinhsi\'s ATK by 25%, stacking up to 2 time(s) and lasting for 20s.\r\n', 'Sequence_Node_Celestial_Incarnate.png', 'Benevolent Grace', 'When Jinhsi casts Resonance Liberation Purge of Light or Resonance Skill Illuminous Epiphany, all nearby Resonators on the team gain 20% Attribute DMG Bonus for 20s.', 'Sequence_Node_Benevolent_Grace.png', 'Frostfire Illumination\r\n', 'The DMG Multiplier of Resonance Liberation Purge of Light is increased by 120%.', 'Sequence_Node_Frostfire_Illumination.png', 'Thawing Triumph', 'The DMG Multiplier of Resonance Skill Illuminous Epiphany is increased by 45% and the additional DMG Multiplier gained by consuming Incandescence is increased by 45%.', 'Sequence_Node_Thawing_Triumph.png', 27, 28, 25, 39, 'Resonator_Jinhsi.png');
INSERT INTO `characters` (`id`, `name`, `element`, `weapon`, `rarity`, `guide_content`, `image_url`, `mat_1`, `mat_2`, `mat_3_tier1`, `mat_3_tier2`, `mat_3_tier3`, `mat_3_tier4`, `hp_base`, `hp_max`, `atk_base`, `atk_max`, `def_base`, `def_max`, `rec_wp_1`, `rec_wp_2`, `rec_wp_3`, `rec_echo_1`, `rec_sonata_1`, `build_1_name`, `best_stat_1`, `best_stat_2`, `best_stat_3`, `best_stat_4`, `best_stat_5`, `skill_normal_name`, `skill_normal_desc`, `skill_resonance_name`, `skill_resonance_desc`, `skill_forte_name`, `skill_forte_desc`, `skill_liberation_name`, `skill_liberation_desc`, `skill_intro_name`, `skill_intro_desc`, `skill_outro_name`, `skill_outro_desc`, `skill_inherent1_name`, `skill_inherent1_desc`, `skill_inherent2_name`, `skill_inherent2_desc`, `skill_normal_icon`, `skill_resonance_icon`, `skill_forte_icon`, `skill_liberation_icon`, `skill_intro_icon`, `skill_outro_icon`, `skill_inherent1_icon`, `skill_inherent2_icon`, `rc1_name`, `rc1_desc`, `rc1_icon`, `rc2_name`, `rc2_desc`, `rc2_icon`, `rc3_name`, `rc3_desc`, `rc3_icon`, `rc4_name`, `rc4_desc`, `rc4_icon`, `rc5_name`, `rc5_desc`, `rc5_icon`, `rc6_name`, `rc6_desc`, `rc6_icon`, `team_mate_1`, `team_mate_2`, `team_mate_3`, `team_mate_4`, `team_icon_url`) VALUES
(30, 'Yinlin', 'Electro', 'Rectifier', 5, 'Yinlin in Wuthering Waves is a 5 Stars Electro character who wields a Rectifier as their weapon type.\r\n\r\nYinlin is a skilled Patroller and powerful Natural Resonator. After being suspended from her duties at the Public Security Bureau, she must now pursue hidden evils in secrecy.', 'yinlin.jpg', 'Group Abomination Tacet Core', 'Coriolus', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 880, 11000, 32, 400, 105, 1283, 'Stringmaster', 'Cosmic Ripples', 'Augment', 'Tempest Mephis', 'Void Thunder', '• Electro DMG + 10%.\r\n• Electro DMG + 15% after releasing Heavy Attack or Resonance Skill. This effect stacks up to 2 times, each stack lasts 15s.', 'Crit. Rate | >65.0%', 'Crit. DMG | >260.0%', 'ATK | >2000', 'Energy Regen | >120%', NULL, 'Zapstring\'s Dance', 'Basic Attack\r\nYinlin controls the puppet \"Zapstring\" to perform up to 4 attacks, dealing Electro DMG.\r\nHeavy Attack\r\nYinlin consumes STA to control \"Zapstring\", dealing Electro DMG.\r\nMid-air Attack\r\nYinlin consumes STA to control \"Zapstring\" to perform a Mid-air Plunging Attack, dealing Electro DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Electro DMG.', 'Magnetic Roar', 'Magnetic Roar\r\nThe puppet \"Zapstring\" deals Electro DMG to the target, and puts Yinlin in Resonance Skill Execution Mode.\r\nExecution Mode\r\nBasic Attack and Dodge Counter will trigger 1 Electromagnetic Blast when hitting a target. Each stage of Basic Attack or Dodge Counter can only trigger 1 Electromagnetic Blast, up to 4 times.\r\nElectromagnetic Blast\r\nAttack all targets marked with Forte Circuit Sinner\'s Mark, dealing Electro DMG.\r\nLightning Execution\r\nUse Resonance Skill after casting Resonance Skill Magnetic Roar to cast Lightning Execution to attack the target, dealing Electro DMG. If Resonance Skill Lightning Execution is not activated in a while or this Character is switched, this Skill will be put on Cooldown.', 'Chameleon Cipher', 'Chameleon Cipher\r\nWhen Yinlin\'s Judgment Points are full, her Heavy Attack is replaced with Chameleon Cipher, which consumes all Judgment Points to attack the target, dealing Electro DMG. When it hits a target marked with Sinner\'s Mark, the Sinner\'s Mark is replaced with Punishment Mark, lasting for 18s. Chameleon Cipher deals Heavy Attack DMG.\r\nSinner\'s Mark\r\nBasic Attack Zapstring\'s Dance, Resonance Liberation Thundering Wrath, and Intro Skill Roaring Storm apply Sinner\'s Mark to the target on hit. Sinner\'s Mark is removed when Yinlin is switched out.\r\nPunishment Mark\r\nWhen a target marked with Punishment Mark takes damage, Judgement Strike will fall, triggering Coordinated Attacks to all targets marked with Punishment Mark, dealing Electro DMG. This can be triggered up to 1 time per second. Judgement Strike deals Resonance Skill DMG.\r\nJudgment Points\r\nYinlin can hold up to 100 Judgement Points. Yinlin gains Judgement Points through the following ways: Upon casting Intro Skill Raging Storm When Basic Attack Zapstring\'s Dance hits a target Upon casting Resonance Skill Magnetic Roar; When Resonance Skill Electromagnetic Blast hits a target; Upon casting Resonance Skill Lightning Execution.', 'Thundering Wrath', 'Command \"Zapstring\" to call for thunder to fall upon a large range, dealing Electro DMG.', 'Raging Storm', 'Command puppet \"Zapstring\" to attack, dealing Electro DMG in a large range.', 'Strategist', 'The incoming Resonator has their Electro DMG Amplified by 20% and Resonance Liberation DMG Amplified by 25% for 14s or until they are switched out.', 'Pain Immersion', 'After using Resonance Skill Magnetic Roar, Yinlin\'s Crit. Rate is increased by 15% for 5s.', 'Deadly Focus', 'The damage of Resonance Skill Lightning Execution is increased by 10% when hitting targets marked with Sinner\'s Mark, and Yinlin\'s ATK is increased by 10% for 4s when this is triggered.', 'Skill_Rectifier.png', 'Skill_Magnetic_Roar.png', 'Skill_Chameleon_Cipher.png', 'Skill_Thundering_Wrath.png', 'Raging_Storm.png', 'Strategist.png', 'Pain_Immersion.png', 'Deadly_Focus.png', 'Morality\'s Crossroads', 'Resonance Skill Magnetic Roar and Lightning Execution deal 70% more DMG.', 'Sequence_Node_Morality27s_Crossroad.png', 'Ensnared by Interrogation', 'When Resonance Skill hits a target, Yinlin recovers 5 Resonance Energy and 5 Concerto Energy.', 'Sequence_Node_Ensnarled_By_Rapport.png', 'Relentless Pursuit', 'Resonance Liberation Thundering Wrath DMG is increased by 55%.', 'Sequence_Node_Unyielding_Verdict.png', 'Steadfast Strike', 'When Forte Circuit Judgment Strike hits a target, the ATK of all team members is increased by 20% for 12s.', 'Sequence_Node_Steadfast_Conviction.png', 'Resounding Will', 'Resonance Liberation Thundering Wrath deals 100% extra DMG to targets with Forte Circuit\'s Sinner\'s Mark or Punishment Mark.', 'Sequence_Node_Resounding_Will.png', 'Righteous Judgment', 'In the first 30s after casting Resonance Liberation Thundering Wrath, when Yinlin\'s Basic Attack hits a target, Furious Thunder will be triggered, dealing Electro DMG equal to 419.59% of Yinlin\'s ATK. Every Basic Attack hit can trigger Furious Thunder 1 time, up to 4 times. This is considered Resonance Skill DMG.', 'Sequence_Node_Pursuit_of_Justice.png', 36, 26, 39, 46, 'Resonator_Yinlin.png'),
(31, 'Jiyan', 'Aero', 'Broadblade', 5, 'Jiyan in Wuthering Waves is a 5 Stars Aero character who wields a Broadblade as their weapon type.\r\n\r\nJiyan, leader of the Midnight Rangers, acts with swift and resolute righteousness. He possesses the formidable ability to conjure a powerful Qingloong from the winds, making him invincible on the battlefield.', 'jiyan.jpg', 'Roaring Rock Fist', 'Pecok Flower', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 839, 10487, 35, 437, 97, 1185, 'Verdant Summit', 'Lustrous Razor', 'Autumntrace', 'Feilian Beringal', 'Sierra Gale', '• Aero DMG + 10%.\r\n• Aero DMG + 30% for 15s after releasing Intro Skill.', 'Crit. Rate | >70.0%', 'Crit. DMG | >260.0%', 'Energy Regen | >130%', 'ATK | >2000', NULL, 'Lone Lance', 'Basic Attack\r\nPerform up to 5 consecutive attacks, dealing Aero DMG.\r\nHeavy Attack\r\nConsume Stamina to thrust forward, dealing Aero DMG.\r\nHeavy Attack: Windborne Strike\r\nHold Basic Attack during Heavy Attack to cast Windborne Strike after Heavy Attack ends, dealing Aero DMG.\r\nHeavy Attack: Abyssal Slash\r\nRelease Basic Attack during Heavy Attack to cast Abyssal Slash after Heavy Attack ends, dealing Aero DMG.\r\nMid-Air Attack\r\nConsume Stamina to perform a Plunging Attack while in mid-air, dealing Aero DMG. After performing the Plunging Attack, use Basic Attack to perform a follow-up attack, dealing Aero DMG.\r\nMid-Air Attack: Banner of Triumph\r\nAfter casting Heavy Attack Windborne Strike or Resonance Skill Windqueller in mid-air, Jiyan can perform a mid-air attack, dealing Aero DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Aero DMG.', 'Windqueller', 'Dash forward a certain distance, dealing Aero DMG.\r\nCan be cast in the air.', 'Qingloong at War', 'When casting Resonance Skill Windqueller, if Jiyan has 30 or more \"Resolve\", he consumes 30 \"Resolve\" to increase the DMG of this Resonance Skill Windqueller by 20%. When Jiyan is in Qingloong Mode, DMG of Resonance Skill Windqueller is increased by 20% and no longer consumes \"Resolve\".\r\nResonance Liberation: Emerald Storm - Finale\r\nWhen casting Resonance Liberation Emerald Storm - Prelude, if Jiyan has 30 \"Resolve\" or more, he will consume 30 \"Resolve\" to cast Emerald Storm - Finale, dealing Aero DMG, considered as Heavy Attack DMG. Emerald Storm: Finale can be cast in mid-air at low altitude.\r\nResolve\r\nJiyan can hold up to 60 Resolve. Jiyan gains \"Resolve\" when his Normal Attack Lone Lance hits the target. Jiyan gains \"Resolve\" when the Intro Skill Tactical Strike hits the target. \"Resolve\" will gradually decrease if Jiyan does not hit a target within 15s.', 'Emerald Storm - Prelude', 'After releasing Emerald Storm - Prelude, Jiyan enters Qingloong Mode.\r\nQingloong Mode\r\nJiyan has increased resistance to interruption. Basic Attack, Heavy Attack and Dodge Counter are replaced with Heavy Attack Lance of Qingloong.\r\nHeavy Attack: Lance of Qingloong\r\nPerform up to 3 consecutive attacks, dealing Aero DMG, considered as Heavy Attack DMG.', 'Tactical Strike', 'Jiyan pierces the target in mid-air, dealing Aero DMG.', 'Discipline', 'When the incoming Resonator\'s Heavy Attack hits a target, Jiyan will summon a lance to launch a coordinated attack, dealing Aero DMG equal to 313.40% of Jiyan\'s ATK. This attack lasts for 8s and can be triggered once every 1s, up to 2 times.', 'Heavenly Balance', 'After casting the Intro Skill Tactical Strike, Jiyan\'s ATK is increased by 10% for 15s.', 'Tempest Taming', 'When Jiyan\'s attacks hit a target, Jiyan\'s Crit. DMG is increased by 12% for 8s.', 'Skill_Broadblade.png', 'Skill_Windqueller.png', 'Skill_Qingloong_at_War.png', 'Skill_Emerald_Storm_Prelude.png', 'Skill_Tactical_Strike.png', 'Skill_Discipline.png', 'Skill_Heavenly_Balance.png', 'Skill_Tempest_Taming.png', 'Benevolence', 'Resonance Skill Windqueller can be used 1 more time. When casting Resonance Skill Windqueller, the Resolve cost is decreased by 15.', 'Sequence_Node_Benevolence.png', 'Versatility', 'After casting Intro Skill Tactical Strike, Jiyan gains 30 Resolve and his ATK is increased by 28% for 15s. This can be triggered once every 15s.\r\n', 'Sequence_Node_Versatility.png', 'Spectation', 'When casting Resonance Skill Windqueller, Resonance Liberation Emerald Storm: Prelude, Resonance Skill Emerald Storm: Finale or Intro Skill Tactical Strike, Jiyan\'s Crit. Rate is increased by 16% and Crit. DMG is increased by 32% for 8s.', 'Sequence_Node_Spectation.png', 'Prudence', 'When casting Resonance Liberation Emerald Storm: Prelude or Resonance Liberation Emerald Storm: Finale, the Heavy Attack DMG Bonus of all team members is increased by 25% for 30s.', 'Sequence_Node_Prudence.png', 'Resolution', 'Outro Skill Discipline gains an additional DMG Multiplier of 120%. When Jiyan\'s attacks hit a target, his ATK is increased by 3% for 8s, stacking up to 15 times; this effect is immediately maxed after he casts Intro Skill Tactical Strike.', 'Sequence_Node_Resolution.png', 'Fortitude', 'Every time Heavy Attack, Intro Skill Tactical Strike or Resonance Skill Windqueller is used, Jiyan gains 1 stack(s) of \"Momentum\", stacking up to 2 times. Resonance Liberation Emerald Storm: Finale will consume all \"Momentum\", and each stack consumed increases the DMG multiplier of Resonance Liberation Emerald Storm: Finale by 120%.', 'Sequence_Node_Fortitude.png', 44, 39, 46, 40, 'Resonator_Jiyan.png'),
(33, 'Rover (Havoc)', 'Havoc', 'Sword', 5, 'Rover (Havoc) in Wuthering Waves is a 5 Stars Havoc character who wields a Sword as their weapon type.\r\n\r\nA mysterious Resonator with the power to absorb all sounds. Currently journeying to find their lost memories.', 'rover_havoc.jpg', 'Mysterious Code', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 862, 10775, 35, 437, 93, 1136, 'Emerald of Genesis', 'Lumingloss', 'Commando of Conviction', 'Dreamless', 'Sun-sinking Eclipse', '• Havoc DMG + 10%.\r\n• Havoc DMG + 7.5% after releasing Basic Attack or Heavy Attack. This effect stacks up to 4 times, each stack lasts 15s.', 'Crit. Rate | >65.0%', 'Crit. DMG | >250.0%', 'ATK | >2000', NULL, NULL, 'Tuneslayer', 'Basic Attack\r\nRover-Havoc performs up to 5 consecutive attacks, dealing Havoc DMG.\r\nHeavy Attack\r\nRover-Havoc consumes STA to attack, dealing Havoc DMG. Use Basic Attack after casting Heavy Attack to cast Basic Attack 4.\r\nMid-air Attack\r\nRover-Havoc consumes STA to cast a Mid-Air Plunging Attack, dealing Havoc DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Havoc DMG.', 'Wingblade', 'Transform sound into feathers, dealing Havoc DMG.', 'Umbra Eclipse', 'Devastation\r\nWhen \"Umbra\" is full, hold Basic Attack to cast Devastation to attack the target, dealing Havoc DMG, considered as Heavy Attack DMG.\r\nDark Surge\r\nAfter casting Devastation, Rover enters the Dark Surge state. In this state: -Basic Attack is replaced with Enhanced Basic Attack, which performs up to 5 consecutive attacks, dealing Havoc DMG. -Heavy Attack is replaced with Enhanced Heavy Attack; -Use Basic Attack after casting Enhanced Heavy Attack to cast Heavy Attack Thwackblade to attack the target, dealing Havoc DMG, considered as Heavy Attack DMG. -Use Basic Attack after casting Heavy Attack Thwackblade to cast Enhanced Basic Attack 3 to attack the target, dealing Havoc DMG; -Resonance Skill Wingblade is replaced with Resonance Skill Lifetaker, transforming sounds into blades to attack the target, dealing Havoc DMG.\r\nUmbra\r\nRover can hold up to 100 points of Umbra. Normal Attack Tuneslayer recovers Umbra on hit. Resonance Skill Wingblade recovers Umbra when cast. Resonance Skill Lifetaker recovers Umbra when cast. Intro Skill Instant of Annihilation recovers Umbra when cast.', 'Deadening Abyss', 'Rover gathers resonating sounds to attack targets, dealing Havoc DMG.', 'Xiphoid Interception', 'Attack the target, dealing Havoc DMG.', 'Soundweaver', 'Rover summons a Havoc Field, dealing Havoc DMG of 143.3% of Rover\'s ATK to all targets within the range every 2s for 6s.', 'Metamorphosis', 'In the Dark Surge state, gain 20% Havoc DMG Bonus.', 'Bloodline', 'While in the Dark Surge state, Basic Attack recovers 1 extra Resonance Energy when it hits a target. This effect can be triggered 1 time per second.', 'Skill_Sword.png', 'Skill_Wingblade.png', 'Skill_Umbra_Eclipse.png', 'Skill_Deadening_Abyss.png', 'Skill_Instant_of_Annihilation.png', 'Skill_Soundweaver.png', 'Skill_Metamorph.png', 'Skill_Bleak_Crescendo.png', 'Cryptic Insight', 'Resonance Skill DMG Bonus is increased by 30%.', 'Sequence_Node_Cryptic_Insight.png', 'Waning Crescent', 'Reset Resonance Skill\'s Cooldown when Rover enters the Dark Surge state by casting Heavy Attack Devastation.', 'Sequence_Node_Waning_Crescent.png', 'Surging Resonance', 'In the Dark Surge state, Basic Attack 5 restores HP equal to 10% of total HP lost on hit.', 'Sequence_Node_Surging_Resonance.png', 'Annihilated Silence', 'Heavy Attack Devastation and Resonance Liberation Deadening Abyss reduces enemy\'s Havoc RES by 10% for 20s on hit.', 'Sequence_Node_Annihilated_Silence.png', 'Aeon Symphony', 'In the Dark Surge state, Basic Attack 5 deals an additional Havoc DMG equal to 50% of Basic Attack 5 DMG.', 'Sequence_Node_Aeon_Symphony.png', 'Ebbing Undercurrent', 'In the Dark Surge state, Rover\'s Crit. Rate is increased by 25%.', 'Sequence_Node_Ebbing_Undercurrent.png', 47, 39, 46, 45, 'Resonator_Rover.png'),
(34, 'Rover (Spectro)', 'Spectro', 'Sword', 5, 'Rover (Spectro) in Wuthering Waves is a 5 Stars Spectro character who wields a Sword as their weapon type.\r\n\r\nA mysterious Resonator with the power to absorb all sounds. Currently journeying to find their lost memories.', 'rover_spectro.jpg', 'Mysterious Code', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 862, 10775, 35, 437, 93, 1136, 'Emerald of Genesis', 'Blazing Brilliance', 'Overture', 'Impermanence Heron', 'Moonlit Clouds', '• Spectro DMG + 10%.\r\n• Spectro DMG + 30% for 15s after releasing Intro Skill.', 'Crit. Rate | >60.0%', 'Crit. DMG | >220.0%', 'ATK | >2000', NULL, NULL, 'Vibration Manifestation\r\n', 'Basic Attack\r\nRover performs up to 4 consecutive attacks, dealing Spectro DMG.\r\nHeavy Attack\r\nRover consumes STA to attack the target, dealing Spectro DMG.\r\nHeavy Attack: Resonance\r\nAfter Basic Attack 3 or Heavy Attack, press the Basic Attack button at the right time to perform Heavy Attack Resonance, dealing Spectro DMG.\r\nHeavy Attack: Aftertune\r\nAfter Heavy Attack Resonance or Dodge Counter hits a target, press the Basic Attack button to perform Heavy Attack Aftertune, dealing Spectro DMG.\r\nMid-air Attack\r\nRover consumes STA to perform a Mid-Air Plunging Attack, dealing Spectro DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Spectro DMG.', 'Resonating Slashes\r\n', 'Rover launches an attack forward, dealing Spectro DMG.', 'World in a Grain of Sand', 'Resonance Skill: Resonating Spin\r\nIf \"Diminutive Sound\" exceeds 50 when Resonance Skill is used, Rover consumes 50 \"Diminutive Sound\" to cast Resonating Spin, dealing Spectro DMG, considered as Resonance Skill DMG.\r\nBasic Attack: Resonating Echoes\r\nAfter Resonance Skill Resonating Spin ends, Rover performs Resonating Echoes upon using Basic Attack button. Launch attacks forward, dealing Spectro DMG, considered as Resonance Skill DMG.\r\nDiminutive Sound\r\nRover can hold up to 100 \"Diminutive Sounds\". Rover obtains \"Diminutive Sound\" for every Normal Attack Vibration Manifestation on hit. Rover obtains \"Diminutive Sound\" for every Heavy Attack Aftertune on hit. Rover obtains \"Diminutive Sound\" upon casting Intro Skill Waveshock.', 'Echoing Orchestra', 'Channel Spectro energy to attack the target area, causing a blast after a short delay, dealing Spectro DMG and applying 6 stack(s) of Spectro Frazzle.\r\n\r\n', 'Waveshock', 'Rover attacks the target, dealing Spectro DMG.', 'Instant', 'Generate an area of stasis centered around the incoming Resonator, lasting for 3s.', 'Reticence', 'DMG dealt by Rover\'s Basic Attack Resonating Echoes is increased by 60%.', 'Silent Listener', 'Rover gains 15% ATK increase for 5s upon casting Heavy Attack Resonance.', 'Skill_Sword.png', 'Skill_Resonating_Slashes.png', 'Skill_World_in_a_Grain_of_Sand.png', 'Skill_Echoing_Orchestra.png', 'Skill_Waveshock.png', 'Skill_Instant.png', 'Skill_Reticence.png', 'Skill_Silent_Listener.png', 'Odyssey of Beginnings', 'Rover\'s Crit. Rate is increased by 15% for 7s when casting Resonance Skill Resonating Slashes or Resonance Skill Resonating Spin.', 'Sequence_Node_Odyssey_of_Beginnings.png', 'Microcosmic Murmurs', 'Rover\'s Spectro DMG Bonus is increased by 20%.', 'Sequence_Node_Microcosmic_Murmurs.png', 'Visages of Dust', 'Rover\'s Energy Regen is increased by 20%.', 'Sequence_Node_Visages_of_Dust.png', 'Resonating Lamella', 'When casting Resonance Liberation Echoing Resonance, Rover continuously restores HP for all team members: HP equal to 20% of Rover\'s ATK will be restored every second for 5s.', 'Sequence_Node_Resonating_Lamella.png', 'Temporal Virtuoso', 'Rover\'s Resonance Liberation DMG Bonus is increased by 40%.', 'Sequence_Node_Temporal_Virtuoso.png', 'Echoes of Wanderlust', 'Resonance Skill Resonating Slashes and Resonance Skill Resonating Spin reduces the target\'s Spectro RES by 10% on hit for 20s.', 'Sequence_Node_Echoes_of_Wanderlust.png', 39, 46, 41, 44, 'Resonator_Rover.png'),
(35, 'Jianxin', 'Aero', 'Gauntlets', 5, 'Jianxin in Wuthering Waves is a 5 Stars Aero character who wields a Gauntlets as their weapon type.\r\n\r\nJianxin, a Taoist monk and successor of Fengyiquan, has dedicated her life to mastering the ultimate martial art. With the power to harness and transform environmental Chi, she can create protective barriers that purify both body and mind.', 'jianxin.jpg', 'Roaring Rock Fist', 'Lanternberry', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 1129, 14112, 27, 337, 92, 1124, 'Verity\'s Handle', 'Abyss Surges', 'Marcato', 'Impermanence Heron', 'Moonlit Clouds', '• Energy Regen + 10%.\r\n• Upon using Outro Skill, increases the ATK of the next Resonator by 22.5% for 15s.', 'Crit. Rate | >65.0%', 'Crit. DMG | >275.0%', 'Energy Regen | >130.0%', '', NULL, 'Fengyiquan', 'Basic Attack\r\nJianxin performs up to 4 consecutive attacks, dealing Aero DMG.\r\nHeavy Attack\r\nJianxin consumes STA to attack the target, dealing Aero DMG.\r\nMid-air Attack\r\nJianxin consumes STA to plunge and unleash a powerful kick, dealing Aero DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Aero DMG.', 'Calming Air', 'Hold Resonance Skill to enter Parry Stance.\r\nChi Counter\r\nWhen Jianxin is attacked in the Parry Stance, she does not take damage and immediately performs Chi Counter, dealing Aero DMG.\r\nChi Parry\r\nRelease the Resonance Skill button during Parry Stance to interrupt Parry Stance and perform Chi Parry, dealing Aero DMG.', 'Primordial Chi Spiral', 'Heavy Attack: Primordial Chi Spiral\r\nWhen \"Chi\" reaches max stacks, hold Basic Attack to cast Primordial Chi Spiral and start Zhoutian Progress.\r\nZhoutian Progress\r\nJianxin\'s resistance to interruption is increased, and her the damage taken is reduced by 50%: Jianxin continuously consumes \"Chi\" and casts Chi Strike to attack targets nearby, dealing Aero DMG. As Zhoutian Progress accumulates, Jianxin reaches different Zhoutian and gains effects accordingly. -Before Minor Zhoutian: Gain Zhoutian Progress 1 shield. When Zhoutian Progress is interrupted, cast Pushing Punch to attack the target, dealing Aero DMG. -Minor Zhoutian: Gain Zhoutian Progress 2 shield and cast Shock to attack the target, dealing Aero DMG. When Zhoutian Progress is interrupted, cast Yielding Pull to attack the target, dealing Aero DMG. -Major Zhoutian - Inner: Gain Zhoutian Progress 3 shield and cast Shock to attack the target, dealing Aero DMG. When Zhoutian Progress is interrupted, cast Yielding Pull to attack the target, dealing Aero DMG. -Major Zhoutian - Outer: Gain Zhoutian Progress 3 shield and cast Shock to attack the target, dealing Aero DMG. -When Basic Attack button is released, interrupt Zhoutian Progress and lose all \"Chi\"; -When all \"Chi\" is consumed, end Zhoutian Progress.\r\nWhen Zhoutian Progress ends, regain a shield according to the Zhoutian Progress reached; As the shield provided by Heavy Attack: Primordial Chi Spiral persists, the active character is healed once every 6s.\r\nChi\r\nJianxin can hold up to 120 Chi. Chi is obtained when Normal Attack Fengyiquan hits the target. Chi is obtained when the Resonance Skill Calming Air is cast. Chi is obtained when the Resonance Skills Chi Counter or Chi Parry hits the target. Chi is obtained when the Intro Skill Essence of Tao hits the target.\r\n\r\n', 'Purification Force Field', 'Create a strong wind field, continuously pulling targets within the wind field to the center and dealing Aero DMG. When the wind field disappears, it will trigger an explosion to deal Aero DMG to all targets within the range again.', 'Essence of Tao\r\n', 'Pull in targets within the range, dealing Aero DMG.', 'Transcendence', 'The incoming Resonator has their Resonance Liberation DMG Amplified by 38% for 14s or until they are switched out.', 'Formless Release', 'Damage of Resonance Liberation Purification Force Field is increased by 20%.', 'Reflection', 'The Shield obtained from Heavy Attack Primordial Chi Spiral is increased by 20%.', 'Skill_Gauntlets.png', 'Skill_Calming_Air.png', 'Skill_Primordial_Chi_Spiral.png', 'Skill_Purification_Force_Field.png', 'Skill_Essence_of_Tao.png', 'Skill_Transcendence.png', 'Skill_Formless_Release.png', 'Skill_Reflection.png', 'Verdant Branchlet', 'After casting Intro Skill Essence of Tao, Jianxin gains 100% extra Chi from Basic Attacks for 10s.', 'Sequence_Node_Verdant_Branchlet.png', 'Tao Seeker\'s Journey', 'Resonance Skill Calming Air can be used 1 more time.', 'Sequence_Node_Tao_Seeker27s_Journey.png', 'Principles of Wuwei', 'After staying in the Parry Stance of Resonance Skill Calming Air for 2.5s, Resonance Skill Chi Counter becomes immediately available.', 'Sequence_Node_Principles_of_Wuwei.png', 'Multitide Reflection', 'When performing Forte Circuit Heavy Attack: Primordial Chi Spiral, Jianxin\'s Resonance Liberation Purification Force Field DMG is increased by 80% for 14s.', 'Sequence_Node_Multitide_Reflection.png', 'Mirroring Introspection', 'The range of Resonance Liberation Purification Force Field is increased by 33%.', 'Sequence_Node_Mirroring_Introspection.png', 'Truth from Within', 'During Forte Circuit Heavy Attack: Primordial Qi Spiral, if Jianxin performs Pushing Punch, enhanced Resonance Skill Special Chi Counter can be used 1 time(s) in 5s. Special Chi Counter: Deals Aero DMG equal to 556.67% of Jianxin\'s ATK, considered as Heavy Attack DMG. Obtain a Zhoutian Progress 4 Shield (Benefits from Inherent Skill Reflection\'s bonus effect.)', 'Sequence_Node_Truth_from_Within.png', 26, 33, 44, 25, 'Resonator_Jianxin.png'),
(36, 'Calcharo', 'Electro', 'Broadblade', 5, 'Calcharo in Wuthering Waves is a 5 Stars Electro character who wields a Broadblade as their weapon type.\r\n\r\nLeader of the \"Ghost Hounds,\" an international mercenary group. Ruthless, vengeful, unforgiving. His Forte allows him to summon a special Tacet Discord to assist his assault on the targets. A potential client must be mindful of the price to pay before making him an offer.', 'calcharo.jpg', 'Thundering Tacet Core', 'Iris', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 840, 10500, 35, 437, 97, 1185, 'Lustrous Razor', 'Ages of Harvest', 'Verdant Summit', 'Thundering Mephis', 'Void Thunder', '• Electro DMG + 10%.\r\n• Electro DMG + 15% after releasing Heavy Attack or Resonance Skill. This effect stacks up to 2 times, each stack lasts 15s.', 'Crit. Rate | >65.0%', 'Crit. DMG | >240.0%', 'ATK | >2200', NULL, NULL, 'Gnawing Fangs', 'Basic Attack\r\nCalcharo performs up to 4 consecutive attacks, dealing Electro DMG.\r\nHeavy Attack\r\nConsumes STA to attack the target, dealing Electro DMG.\r\nMid-air Attack\r\nConsumes STA to perform a Mid-Air Plunging Attack, dealing Electro DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Electro DMG.', 'Extermination Order', 'Calcharo performs up to 3 consecutive attacks, dealing Electro DMG. If Calcharo is switched off field, or if Resonance Skill Extermination Order is not activated again in a while, this skill will enter Cooldown. Resonance Skill Extermination Order does not interrupt Calcharo\'s Basic Attack cycle.', 'Hunting Mission', 'Heavy Attack: \"Mercy\"\r\nWhen Calcharo has 3 \"Cruelty\", his Heavy Attack is replaced with Heavy Attack \"Mercy.\" When casting Heavy Attack \"Mercy\", Calcharo consumes 3 \"Cruelty\" to deal Electro DMG, considered as Heavy Attack DMG, and recovers Resonance Energy and Concerto Energy.\r\n\"Cruelty\"\r\nCalcharo can hold up to 3 \"Cruelty.\" In Resonance Liberation Deathblade Gear state, \"Cruelty\" cannot be acquired. When Resonance Skill Extermination Order hits the target, gain 1 \"Cruelty.\"\r\nHeavy Attack: \"Death Messenger\"\r\nWhen Calcharo has 5 \"Killing Intent\", his Basic Attack is replaced with Heavy Attack \"Death Messenger.\" When casting Heavy Attack \"Death Messenger,\" Calcharo consumes 5 \"Killing Intent\" to deal Electro DMG, considered as Resonance Liberation DMG, and recovers Resonance Energy and Concerto Energy.\r\n\"Killing Intent\"\r\nIn Resonance Liberation Deathblade Gear state, Calcharo\'s Forte Gauge is replaced with \"Killing Intent\", stacking up to 5. When Basic Attack Hounds Roar hits the target, Calcharo gains 1 \"Killing Intent.\"', 'Phantom Etching', 'Calcharo attacks the target, dealing Electro DMG and enters Deathblade Gear state. After Deathblade Gear state ends, Calcharo\'s next Intro Skill is replaced with Intro Skill \"Necessary Means\", which deals Electro DMG, considered as Intro Skill DMG.\r\nDeathblade Gear\r\n-Basic Attack is replaced with Basic Attack Hounds Roar. -Heavy Attack deals increased DMG, considered as Resonance Liberation DMG. -Dodge Counter deals increased DMG, considered as Resonance Liberation DMG.\r\nBasic Attack: Hounds Roar\r\nCalcharo performs up to 5 consecutive attacks, dealing Electro DMG, considered as Basic Attack DMG.\r\n\r\nShow Skill Details', 'Wanted Outlaw', 'Attack the target, dealing Electro DMG.', 'Shadowy Raid', 'Calcharo summons Phantom to support the active Resonator, clearing the targets in front with a slash. The Phantom\'s attack deals Electro DMG equal to 195.98%+391.96% of Calcharo\'s ATK.', 'Bloodshed Awaken', 'Casting Heavy Attack Mercy gives Calcharo 10% Resonance Liberation DMG Bonus for 15s.', 'Revenant Rush', 'When Heavy Attack \"Death Messenger\" hits the target, the damage taken by Calcharo is reduced by 15% for 5s.', 'Skill_Broadblade.png', 'Skill_Extermination_Order.png', 'Skill_Hunting_Mission.png', 'Skill_Phantom_Etching.png', 'Skill_Wanted_Outlaw.png', 'Skill_Shadowy_Raid.png', 'Skill_Bloodshed_Awaken.png', 'Skill_Revenant_Rush.png', 'Covert Negotiation', 'When Resonance Skill Extermination Order hits a target, it additionally recovers 10 Resonance Energy. This can be triggered once every 20s.', 'Sequence_Node_Covert_Negotiation.png', 'Zero-Sum Game', 'After Calcharo casts Intro Skill Wanted Criminal or Intro Skill \"Necessary Means\", his Resonance Skill DMG Bonus is increased by 30% for 15s.', 'Sequence_Node_Zero-Sum_Game.png', 'Iron Fist Diplomacy', 'During the Resonance Liberation Deathblade Gear state, Calcharo\'s Electro DMG Bonus is increased by 25%.', 'Sequence_Node_Iron_Fist_Diplomacy.png', 'Dark Alliance', 'After casting Outro Skill Shadowy Raid, Electro DMG Bonus of all team members is increased by 20% for 30s.', 'Sequence_Node_Dark_Alliance.png', 'Unconventional Compact', 'Intro Skill Wanted Criminal and Intro Skill \"Necessary Means\" deal 50% more DMG.', 'Sequence_Node_Unconventional_Compact.png', 'The Ultimatum', 'When casting Resonance Liberation \"Death Messenger\", Calcharo will summon 2 Phantoms to perform Coordinated Attacks. Each Phantom deals Electro DMG equal to 100.00% of Calcharo\'s ATK, which is considered Resonance Liberation DMG.', 'Sequence_Node_The_Ultimatum.png', 30, 26, 25, 39, 'Resonator_Calcharo.png'),
(37, 'Encore', 'Fusion', 'Rectifier', 5, 'Encore in Wuthering Waves is a 5 Stars Fusion character who wields a Rectifier as their weapon type.\r\n\r\nA girl accompanied by one black and one white Wooly. Encore, consultant from the Black Shores, dreams of creating happy stories with candies, fairy tales, and her imagination.', 'encore.jpg', 'Rage Tacet Core', 'Pecok Flower', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 841, 10512, 34, 425, 102, 1246, 'Stringmaster', 'Rime-Draped Sprouts', 'Cosmic Ripples', 'Inferno Rider', 'Molten Rift', '• Fusion DMG + 10%.\r\n• Fusion DMG + 30% for 15s after releasing Resonance Skill.', 'Crit. Rate | >65.0%', 'Crit. DMG | >25.0%', NULL, NULL, NULL, 'Wooly Attack', 'Basic Attack\r\nEncore performs up to 4 consecutive attacks, dealing Fusion DMG.\r\nBasic Attack: Wooly Strike\r\nAfter Basic Attack 4, press the Normal Attack button to attack the target, dealing Fusion DMG.\r\nHeavy Attack\r\nEncore consumes STA to attack the target, dealing Fusion DMG.\r\nMid-air Attack\r\nEncore consumes STA to perform a Mid-Air Plunging Attack, dealing Fusion DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Fusion DMG.', 'Flaming Woolies', 'Flaming Woolies\r\nEncore summons Cloudy and Cosmos to attack with burning rays, dealing Fusion DMG.\r\nEnergetic Welcome\r\nAfter casting Flaming Woolies, use Resonance Skill to perform Energetic Welcome, dealing Fusion DMG.', 'Black & White Woolies', 'Heavy Attack: Cloudy Frenzy\r\nWhen Encore\'s \"Mayhem\" is full, after casting a Heavy Attack, Encore will consume all \"Mayhem\" to enter the Mayhem state, reducing damage taken by 70%. Switching Characters does not interrupt the Mayhem state. After the Mayhem state ends, Encore will cast Cloudy Frenzy, dealing Fusion DMG, considered as Resonance Liberation damage.\r\nHeavy Attack: Cosmos Rupture\r\nDuring Cosmos Rave, when casting Heavy Attack, if \"Mayhem\" is full, Encore will consume all \"Mayhem\" to enter Cosmos\' Mayhem state, reducing damage taken by 70%. Switching Characters does not interrupt the Cosmos\' Mayhem state. After Cosmos\' Mayhem state ends, Encore will cast Cosmos Rupture, dealing Fusion DMG, considered as Resonance Liberation DMG.\r\nMayhem\r\nEncore can hold up to 100 \"Mayhem\". When Normal Attack Wooly Attack hits a target, Encore restores \"Mayhem\". When Resonance Skill Flaming Woolies hits a target, Encore restores \"Mayhem\". When Resonance Skill Energetic Welcome hits a target, Encore restores \"Mayhem\". When Intro Skill Woolies Helpers hits a target, Encore restores \"Mayhem\". During the duration of Resonance Liberation Cosmos Rave, Encore restores \"Mayhem\" when hitting a target.', 'Cosmos Rave', 'As Encore loses control, Cosmos breaks free and wreaks havoc on its surroundings.\r\nBasic Attack: Cosmos - Frolicking\r\nDuring Cosmos Rave, the Basic Attack is replaced with Cosmos - Frolicking, which performs up to 4 consecutive attacks, dealing Fusion DMG, considered as Basic Attack DMG.\r\nCosmos: Heavy Attack\r\nDuring Cosmos Rave, the Heavy Attack is replaced with Cosmos - Heavy Attack, consuming STA to attack the target, dealing Fusion DMG, considered as Heavy Attack DMG.\r\nResonance Skill: Cosmos - Rampage\r\nDuring Cosmos Rave, Flaming Woolies is replaced with Cosmos - Rampage, dealing Fusion DMG, considered as Resonance Skill DMG.\r\nCosmos: Dodge Counter\r\nDuring Cosmos Rave, use Basic Attack after a successful Dodge to attack the target, dealing Fusion DMG, considered as Basic Attack DMG.', 'Woolies Helpers', 'Encore pounces at the enemies with Cosmos, dealing Fusion DMG.', 'Thermal Field', 'Encore generates a Thermal Field centered around skill target, with a radius of 3m. Targets inside the Thermal Field are continuously burned, suffering Fusion DMG equal to 176.76% of Encore\'s ATK every 1.5s for 6s.', 'Angry Cosmos', 'During the Resonance Liberation Cosmos Rave, when Encore\'s HP is above 70%, DMG dealt is increased by 10%.', 'Woolies Cheer Dance', 'When Resonance Skill Flaming Woolies or Resonance Skill Cosmos - Rampage is cast, Encore\'s Fusion DMG Bonus is increased by 10% for 10s.', 'Skill_Rectifier.png', 'Skill_Flaming_Woolies.png', 'Skill_Black_26_White_Woolies.png', 'Skill_Cosmos_Rave.png', 'Skill_Woolies_Can_Help21.png', 'Skill_Thermal_Field.png', 'Skill_Angry_Cosmos.png', 'Skill_Woolies_Cheer_Dance.png', 'Wooly\'s Fairy Tale', 'When Basic Attack hits a target, Encore\'s Fusion DMG Bonus is increased by 3%, stacking up to 4 time(s) for 6s.', 'Sequence_Node_Wooly27s_Fairy_Tale.png', 'Sheep-counting Lullaby', 'Encore additionally restores 10 Resonance Energy when casting Basic Attack Wooly Strike or Resonance Skill Energetic Welcome. This can be triggered once every 10s.', 'Sequence_Node_Sheep-counting_Lullaby.png', 'Fog? The Black Shores!', 'The DMG multiplier of Heavy Attack Cloudy Frenzy and Heavy Attack Cosmos Rupture is increased by 40%.', 'Sequence_Node_Fog21.png', 'Adventure? Let\'s go!', 'Heavy Attack Cosmos Rupture increases the Fusion DMG Bonus of all team members by 20% for 30s.', 'Sequence_Node_Adventure27s_go21.png', 'Hero Takes the Stage!', 'Resonance Skill DMG Bonus is increased by 35%.', 'Sequence_Node_Hero_Takes_the_Stage21.png', 'Woolies Save the World!\r\n', 'During Resonance Liberation Cosmos Rave, Encore gains 1 stack(s) of \"Lost Lamb\" every time she deals damage, each stack increasing her ATK by 5% for 10s, stacking up to 5 time(s).', 'Sequence_Node_Woolies_Save_the_World21.png', 28, 45, 25, 39, 'Resonator_Encore.png'),
(38, 'Lingyang', 'Glacio', 'Gauntlets', 5, 'Lingyang in Wuthering Waves is a 5 Stars Glacio character who wields a Gauntlets as their weapon type.\r\n\r\nAn enthusiastic, brave member of the Liondance Troupe in Jinzhou, Lingyang is a sincere, compassionate visitor of the human community with incredible physical abilities, whose interest in humans easily shows. With his unique style, he embodies the spirit of Liondance.', 'lingyang.jpg', 'Sound-Keeping Tacet Core', 'Coriolus', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 831, 10387, 35, 437, 99, 1209, 'Abyss Surges', 'Hollow Mirage', 'Stonard', 'Lampylumen Myriad', 'Freezing Frost', '• Glacio DMG + 10%.\r\n• Glacio DMG + 10% after releasing Basic Attack or Heavy Attack. This effect stacks up to 3 times, each stack lasts 15s.', 'Crit. Rate | >60.0%', 'Crit. DMG | >260.0%', 'Energy Regen | >120.0%', NULL, NULL, 'Majestic Fists\r\n', 'Basic Attack\r\nLingyang performs up to 5 consecutive attacks, dealing Glacio DMG.\r\nBasic Attack: Feral Roars\r\nAfter Resonance Skill Furious Punches is cast, Basic Attack 5 is replaced with Feral Roars, dealing Glacio DMG.\r\nHeavy Attack\r\nLingyang consumes STA to attack the target, dealing Glacio DMG.\r\nMid-air Attack\r\nLingyang consumes STA to perform a Mid-air Plunging Attack, dealing Glacio DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Glacio DMG.', 'Ancient Arts', 'Ancient Arts\r\nAttack the target, dealing Glacio DMG.\r\nFurious Punches\r\nWhen Basic Attacks 3, 4, or 5 or Basic Attack Feral Roars hits the target, Resonance Skill Ancient Arts is replaced with Resonance Skill Furious Punches. Lingyang\'s Basic Attack cycle starts from Basic Attack 3 after casting Basic Attack Feral Roars and Resonance Skill Furious Punches in turn.\r\nLingyang\'s Resonance Skill does not reset his Basic Attack cycle.', 'Unification of Spirits\r\n', 'Heavy Attack: Glorious Plunge\r\nWhen \"Lion\'s Spirit\" is full, use Heavy Attack to perform Glorious Plunge, dealing Glacio DMG.\r\nMid-air Attack: Tail Strike\r\nWhen \"Lion\'s Spirit\" is not full, use Basic Attack after Heavy Attack to perform Tail Strike, dealing Glacio DMG.\r\nStriding Lion\r\nAfter casting Heavy Attack Glorious Plunge, enter Striding Lion state; After casting Intro Skill Lion Awakens or Resonance Liberation Strive: Lion\'s Vigor, if \"Lion\'s Spirit\" is full, use Basic Attack to enter Striding Lion state. In the Striding Lion state: -Attacks can be launched in mid-air. If Lingyang is on the ground, use Heavy Attack Glorious Plunge to get back in the air. -\"Lion\'s Spirit\" is continuously consumed before running out in 5s, and when it runs out, Striding Lion ends; -If Lingyang is in the Resonance Liberation Lion\'s Vigor state, the consumption speed of \"Lion\'s Spirit\" is reduced by 50%, extending Striding Lion state by up to 10s. -Lingyang\'s Basic Attack is replaced with Basic Attack Feral Gyrate, which performs up to 2 consecutive attacks, dealing Glacio DMG; -Lingyang\'s Resonance Skill is replaced with Mountain Roamer, dealing Glacio DMG; -When \"Lion\'s Spirit\" is less than 10, use Basic Attack to perform Stormy Kicks, dealing Glacio DMG; after performing Basic Attack Stormy Kicks, the Mid-air Attack Tail Strike becomes available. -Concerto Energy is restored when \"Lion\'s Spirit\" is consumed.\r\nLion\'s Spirit\r\nLingyang can hold up to 100 \"Lion\'s Spirit\". When casting Resonance Skill Furious Punches, \"Lion\'s Spirit\" is restored. When casting Intro Skill Lion Awakens, \"Lion\'s Spirit\" is restored. When casting Resonance Liberation Strive: Lion\'s Vigor, \"Lion\'s Spirit\" is restored.', 'Strive: Lion\'s Vigor', 'Attack the target, dealing Glacio DMG, and receive the blessing of Lion\'s Vigor.\r\nLion\'s Vigor\r\nLingyang gains 50% Glacio DMG Bonus.', 'Lion Awakens', 'Lingyang enters the battlefield, dealing Glacio DMG.', 'Frosty Marks\r\n', 'Lingyang releases a shock wave centered on the skill target, dealing Glacio DMG equal to 587.94% of Lingyang\'s ATK to targets within the range.', 'Lion\'s Pride', 'DMG of the Intro Skill Lion Awakens is increased by 50%.', 'Diligent Practice', 'Under the Forte Circuit Striding Lion state, within 3s after each Basic Attack, the next Forte Circuit Mountain Roamer will deal an additional Glacio DMG, equal to 150% of Mountain Roamer DMG, considered as Resonance Skill DMG.', 'Skill_Majestic_Fists.png', 'Skill_Ancient_Arts.png', 'Skill_Unification_of_Spirits.png', 'Skill_Strive-Lion27s_Vigor.png', 'Skill_Lion_Awakens.png', 'Skill_Frosty_Marks.png', 'Skill_Lion27s_Pride.png', 'Skill_Diligent_Practice.png', 'Lion of Light, Blessings Abound', 'During Resonance Liberation Lion\'s Vigor, Lingyang\'s Anti-Interruption is enhanced.', 'Sequence_Node_Lion_of_Light2C_Blessings_Abound.png', 'Dominant and Fierce, Power Unbound', 'Intro Skill Lion Awakens additionally recovers 10 Resonance Energy for Lingyang, triggered once every 20s.', 'Sequence_Node_Dominant_and_Fierce2C_Power_Unbound.png', 'Jaw-Dropping Feats, Loud and Wide', 'During Resonance Liberation Lion\'s Vigor, Lingyang\'s Basic Attack DMG Bonus is increased by 20%, and Resonance Skill DMG Bonus increased by 10%.', 'Sequence_Node_Jaw-Dropping_Feats2C_Loud_and_Wide.png', 'Immortals Bow, in Reverence Flawed', 'Outro Skill Frosty Marks increases the Glacio DMG Bonus of all team members by 20% for 30s.', 'Sequence_Node_Immortals_Bow2C_in_Reverence_Flawed.png', 'Seven Stars Shine, Stepped upon High', 'Resonance Liberation Strive: Lion\'s Vigor additionally deals Glacio DMG equal to 200% of Lingyang\'s ATK.', 'Sequence_Node_Seven_Stars_Shine2C_Stepped_upon_High.png', 'Demons Tremble, Divine Power Nigh', 'In the Forte Circuit Striding Lion state, during the first 3s after every Resonance Skill Mountain Roamer, the Basic Attack DMG Bonus for Lingyang\'s next Basic Attack is increased by 100%.', 'Sequence_Node_Demons_Tremble2C_Divine_Power_Nigh.png', 27, 45, 25, 39, 'Resonator_Lingyang.png'),
(39, 'Verina', 'Spectro', 'Rectifier', 5, 'Verina in Wuthering Waves is a 5 Stars Spectro character who wields a Rectifier as their weapon type.\r\n\r\nWith an extensive knowledge of botany, Verina is always solicitous, always smiling, and always wishing for every flower to be blessed with the miracle of life.', 'verina.jpg', 'Elegy Tacet Core', 'Belle Poppy', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 1139, 14237, 27, 337, 90, 1099, 'Stellar Symphony', 'Cosmic Ripples', 'Variation', 'Fallacy of No Return', 'Rejuvenating Glow', '• Healing Bonus + 10%.\r\n• Increases the ATK of all party members by 15% for 30s upon healing allies.', 'Energy Regen | >70.0%', 'ATK | >1500', NULL, NULL, NULL, 'Cultivation', 'Basic Attack\r\nVerina performs up to 5 consecutive attacks with vines, dealing Spectro DMG.\r\nHeavy Attack\r\nVerina consumes STA to charge forward, dealing Spectro DMG.\r\nMid-air Attack\r\nVerina consumes STA to perform up to 3 consecutive attacks in mid-air, dealing Spectro DMG.\r\nMid-air Heavy Attack\r\nHold Basic Attack to consume STA and perform a mid-air Plunging Attack, dealing Spectro DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Spectro DMG.', 'Botany Experiment\r\n', 'Verina converges an energy field in front to grow foliage, dealing Spectro DMG within the range.', 'Starflower Blooms', 'Heavy Attack: Starflower Blooms\r\nWhen casting Heavy Attack, if Verina carries \"Photosynthesis Energy\", Verina consumes 1 stack of \"Photosynthesis Energy\" to recover Concerto Energy and heal all characters on a nearby team. Heavy Attack: Starflower Blooms deals Spectro DMG, considered as Heavy Attack DMG.\r\nMid-air Attack: Starflower Blooms\r\nWhen casting Mid-air Attack, if Verina carries \"Photosynthesis Energy\", Verina consumes 1 stack of \"Photosynthesis Energy\" to recover Concerto Energy and heal all characters on a nearby team. Mid-air Attack: Starflower Blooms deals Spectro DMG, considered as Basic Attack DMG. Verina can cast Mid-air Attack: Starflower Blooms by using Basic Attack after casting Heavy Attack: Starflower Blooms.\r\nPhotosynthesis Energy\r\nVerina can hold up to 4 stacks of \"Photosynthesis Energy\". Verina obtains 1 stack of \"Photosynthesis Energy\" for every Basic Attack 5 on hit. Verina obtains 1 stack of \"Photosynthesis Energy\" after casting Resonance Skill Botany Experiment. Verina obtains 1 stack of \"Photosynthesis Energy\" after casting Intro Skill Verdant Growth.', 'Arboreal Flourish\r\n', 'Verina nourishes nearby foliage at rapid speed, dealing Spectro DMG while healing all Characters on teams nearby. A Photosynthesis Mark is applied to the target on hit.\r\nPhotosynthesis Mark\r\nWhenever a Character on a team nearby performs an attack on targets with a Photosynthesis Mark, Verina performs a Coordinated Attack, dealing Spectro DMG while healing the active Character dealing damage on a team nearby, triggered 1 time per second.', 'Verdant Growth\r\n', 'Verina attacks the target, dealing Spectro DMG.', 'Blossom', 'Heal the incoming Resonator by 19% of Verina\'s ATK per second for 6s. All Resonators on nearby teams have their DMG Amplified by 15% for 30s.', 'Grace of Life', 'Verina protects a team member from fatal damage and grants a shield with strength equal to 120% of Verina\'s ATK, lasting for 10s. This can be triggered 1 time every 10 minutes.', 'Gift of Nature', 'When Verina casts Heavy Attack Starflower Blooms, Mid-air Attack Starflower Blooms, Resonance Liberation Arboreal Flourish or Outro Skill Blossom, all team members\' ATK are increased by 20% for 20s.', 'Skill_Rectifier.png', 'Skill_Botany_Experiment.png', 'Skill_Starflower_Blooms.png', 'Skill_Arboreal_Flourish.png', 'Skill_Verdant_Growth.png', 'Skill_Blossom.png', 'Skill_Grace_of_Life.png', 'Skill_Gift_of_Nature.png', 'Moment of Emergence', 'Outro Skill Blossom grants the next character a continuous Healing effect, recovering HP by 20% of Verina\'s ATK every 5s for 30s.', 'Sequence_Node_Moment_of_Emergence.png', 'Sprouting Reflections', 'Resonance Skill Botany Experiment additionally grants 1 [Photosynthesis Energy] and 10 Concerto Energy.', 'Sequence_Node_Sprouting_Reflections.png', 'The Choice to Flourish', 'Healing of Resonance Liberation\'s Photosynthesis Mark is increased by 12%.', 'Sequence_Node_The_Choice_to_Flourish.png', 'Blossoming Embrace', 'Heavy Attack Starflower Blooms, Mid-Air Attack Starflower Blooms, Resonance Liberation Arboreal Flourish and Outro Skill Blossom increases the Spectro DMG Bonus of all team members by 15% for 24s.', 'Sequence_Node_Blossoming_Embrace.png', 'Miraculous Blooms', 'When Verina heals a team member with HP less than 50%, her Healing is increased by 20%.', 'Sequence_Node_Miraculous_Blooms.png', 'Joyous Harvest', 'Heavy Attack Starflower Blooms and Mid-air Attack Starflower Blooms deal 20% more DMG. They will trigger Coordinated Attack 1 time and heal all characters nearby. The damage of this Coordinated Attack and the Healing are equal to those of the Resonance Liberation\'s Photosynthesis Mark.', 'Sequence_Node_Joyous_Harvest.png', 29, 28, 27, 45, 'Resonator_Verina.png');
INSERT INTO `characters` (`id`, `name`, `element`, `weapon`, `rarity`, `guide_content`, `image_url`, `mat_1`, `mat_2`, `mat_3_tier1`, `mat_3_tier2`, `mat_3_tier3`, `mat_3_tier4`, `hp_base`, `hp_max`, `atk_base`, `atk_max`, `def_base`, `def_max`, `rec_wp_1`, `rec_wp_2`, `rec_wp_3`, `rec_echo_1`, `rec_sonata_1`, `build_1_name`, `best_stat_1`, `best_stat_2`, `best_stat_3`, `best_stat_4`, `best_stat_5`, `skill_normal_name`, `skill_normal_desc`, `skill_resonance_name`, `skill_resonance_desc`, `skill_forte_name`, `skill_forte_desc`, `skill_liberation_name`, `skill_liberation_desc`, `skill_intro_name`, `skill_intro_desc`, `skill_outro_name`, `skill_outro_desc`, `skill_inherent1_name`, `skill_inherent1_desc`, `skill_inherent2_name`, `skill_inherent2_desc`, `skill_normal_icon`, `skill_resonance_icon`, `skill_forte_icon`, `skill_liberation_icon`, `skill_intro_icon`, `skill_outro_icon`, `skill_inherent1_icon`, `skill_inherent2_icon`, `rc1_name`, `rc1_desc`, `rc1_icon`, `rc2_name`, `rc2_desc`, `rc2_icon`, `rc3_name`, `rc3_desc`, `rc3_icon`, `rc4_name`, `rc4_desc`, `rc4_icon`, `rc5_name`, `rc5_desc`, `rc5_icon`, `rc6_name`, `rc6_desc`, `rc6_icon`, `team_mate_1`, `team_mate_2`, `team_mate_3`, `team_mate_4`, `team_icon_url`) VALUES
(40, 'Aalto', 'Aero', 'Pistols', 4, 'Aalto in Wuthering Waves is a 4 Stars Aero character who wields a Pistols as their weapon type.\r\n\r\nAalto is an enigmatic Information Broker, known for his elusive nature and welcoming smile. Underneath the facade, he is closely affiliated with the Black Shores. Rumor has it he\'ll provide any information at the right price.', 'aalto.jpg', 'Roaring Rock Fist', 'Wintry Bell', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 788, 9850, 21, 262, 88, 1075, 'Static Mist', 'Undying Flame', 'Novaburst', 'Impermanence Heron', 'Moonlit Clouds', '• Energy Regen + 10%.\r\n• Upon using Outro Skill, increases the ATK of the next Resonator by 22.5% for 15s.', 'Crit. Rate | >60.0%', 'Crit. DMG | >200.0%', 'ATK | >2000', NULL, NULL, 'Half Truths', 'Basic Attack\r\nAalto fires up to 5 consecutive shots, dealing Aero DMG. Basic Attack 4 will spread the Mist forward, which lasts for 1.5s.\r\nHeavy Attack\r\nAalto enters the aiming state for a more powerful shot. The aimed shot fired after charging finishes deals Aero DMG.\r\nMid-air Attack\r\nAalto consumes STA to perform consecutive shots at the target in mid-air, dealing Aero DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Aero DMG.', 'Shift Trick\r\n', 'Mist Avatar\r\nCasts Mist and 1 \"Mist Avatar(s)\" to taunt the surrounding targets. The avatars inherit a portion of Aalto\'s HP and generate 6 Mist Bullets around them, dealing Aero DMG.\r\nMist Bullets\r\nDeals Aero DMG, considered as Resonance Skill DMG.', 'Misty Cover', 'When Aalto passes through \"Mist\" or \"Gate of Quandary\", he enters the Mistcloak Dash.\r\nMistcloak Dash\r\n-Movement speed increased; -During this period, \"Mist Drops\" are continuously consumed, and for each 1 \"Mist Drop\" consumed, 1 Mist Bullet(s) is generated.\r\nMist Drops\r\nAalto can hold up to 6 \"Mist Drops\". When Basic Attack or Mid-air Attack passes through \"Mist\" and hits the target, 1 \"Mist Drop\" is recovered.', 'Flower in the Mist', 'Generate a Gate of Quandary in front, dealing Aero DMG. When bullets pass through the Gate of Quandary, they deal increased DMG. Gate of Quandary lasts for 10s.', 'Feint Shot', 'Aalto shows up out of thin air to perform rapid continuous shooting, dealing Aero DMG.', 'Dissolving Mist', 'The incoming Resonator has their Aero DMG Amplified by 23% for 14s or until they are switched out.', 'Perfect Performance', 'Aalto\'s Heavy Attack will always critically hit, triggered once every 30s.', 'Mid-game Break', 'Aalto will continuously recover STA when he is in the Forte Circuit Mistcloak Dash state.', 'Skill_Pistols.png', 'Skill_Shift_Trick.png', 'Skill_Misty_Cover.png', 'Skill_Flower_in_the_Mist.png', 'Skill_Feint_Shot.png', 'Skill_Dissolving_Mist.png', 'Skill_Perfect_Performance.png', 'Skill_Mid-game_Break.png', 'Trickster\'s Opening Show', 'The cooldown of Resonance Skill Shift Trick is reduced by 4s.', 'Sequence_Node_Trickster27s_Opening_Show.png', 'Mistweaver\'s Debut', '\"Mist Avatar\" inherits 100% more HP from Aalto. When Aalto attacks targets taunted by the \"Mist Avatar(s)\", his ATK is increased by 15%.', 'Sequence_Node_Mistweaver\'s_Debut.png', 'Hazey Transition', 'When Aalto\'s Basic Attack or Mid-air Attack passes through the Mist, 2 more bullets will be generated, dealing 50% of the DMG of Basic Attack or Mid-air Attack.', 'Sequence_Node_Hazey_Transition.png', 'Blake Bloom for Finale', 'The damage of Resonance Skill Mist Bullets is increased by 30%; Aalto receives 30% less DMG in his Forte Circuit Mistcloak Dash state.', 'Sequence_Node_Blake_Bloom_for_Finale.png', 'Applause of the Lost', 'In the Forte Circuit Mistcloak Dash state, Aalto\'s Aero DMG Bonus is increased by 25% for 6s.', 'Sequence_Node_Applause_of_the_Lost.png', 'Broker\'s Secrets', 'Resonance Liberation Flower in the Mist now additionally increases Crit. Rate by 8%. When Aalto\'s Heavy Attack passes through the Gate of Quandary, the damage dealt is additionally increased by 50%.', 'Sequence_Node_Broker27s_Secrets.png', 31, 45, 25, 39, 'Resonator_Aalto.png'),
(41, 'Yangyang', 'Aero', 'Sword', 4, 'Yangyang in Wuthering Waves is a 4 Stars Aero character who wields a Sword as their weapon type.\r\n\r\nYangyang is an Outrider of the Midnight Rangers. Once sheltered, now a fighter. She soars with the wind to protect others, like a skylark in flight.', 'yangyang.jpg', 'Roaring Rock Fist', 'Wintry Bell', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 816, 10200, 20, 250, 90, 1099, 'Emerald of Genesis', 'Blazing Brilliance', 'Lumingloss', 'Bell-Borne Geochelone', 'Moonlit Clouds', '• Energy Regen + 10%.\r\n• Upon using Outro Skill, increases the ATK of the next Resonator by 22.5% for 15s.', 'Crit. Rate | >75.0%', 'Crit. Rate | >240.0%', NULL, NULL, NULL, 'Feather as Blade', 'Basic Attack\r\nYangyang performs up to 4 consecutive attacks, dealing Aero DMG.\r\nHeavy Attack\r\nYangyang consumes STA to lunge forward, dealing Aero DMG.\r\nHeavy Attack: Zephyr Song\r\nUse Basic Attack after Heavy Attack or Dodge Counter to perform Heavy Attack Zephyr Song, dealing Aero DMG.\r\nMid-air Attack\r\nYangyang consumes STA to perform a Plunging Attack from mid-air, dealing Aero DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to thrust forward, dealing Aero DMG.', 'Zephyr Domain\r\n', 'Yangyang wields her sword to create a whirling vortex of winds that pulls nearby enemies to the center, dealing Aero DMG.', 'Echoing Feathers\r\n', 'Heavy Attack: Stormy Strike\r\nWhen Yangyang has 3 Melodies, she can cast Stormy Strike after Heavy Attack or Dodge Counter, dealing Aero DMG.\r\nMid-air Attack: Feather Release\r\nWhen Yangyang has 3 Melodies, cast Basic Attack in mid-air to consume all Melodies and perform consecutive strikes, diving from mid-air, dealing Aero DMG. As Yangyang lands, she sheathes her sword with an attack, dealing Aero DMG, considered as Basic Attack DMG.\r\nMelody\r\nYangyang can hold up to 3 Melodies Yangyang obtains 1 Melody with every Basic Attack 4 on hit. Yangyang obtains 1 Melody for every Heavy Attack Zephyr Song on hit. Yangyang obtains 1 Melody for every Resonance Skill Zephyr Domain on hit. Yangyang obtains 1 Melody upon casting Intro Skill Cerulean Song.', 'Wind Spirals', 'Yangyang conjures a mighty Cyclone that pulls nearby enemies, dealing Aero DMG.', 'Cerulean Song\r\n', 'Yangyang sends the target into the air, dealing Aero DMG.', 'Whispering Breeze\r\n', 'Restore 4 Resonance Energy per second for 5s for the incoming Resonator.', 'Compassion', 'Yangyang recovers 30 STA after she casts a Mid-air Attack Feather Release.', 'Lazuline Mercy', 'Yangyang\'s Aero DMG Bonus is increased by 8% for 8s after casting Intro Skill Cerulean Song.', 'Skill_Sword.png', 'Skill_Zephyr_Domain.png', 'Skill_Echoing_Feathers.png', 'Skill_Wind_Spirals.png', 'Skill_Cerulean_Song.png', 'Skill_Whispering_Breeze.png', 'Skill_Compassion.png', 'Skill_Lazuline_Mercy.png', 'Sapphire Skies, Soaring Sparrows', 'Intro Skill Cerulean Song increases Yangyang\'s Aero DMG Bonus by an additional 15% for 8s.', 'Sequence_Node_Sapphire_Skies2C_Soaring_Sparrows.png', 'Nesting Twigs, in Beaks They Harrow', 'Heavy Attack recovers an additional 10 Resonance Energy for Yangyang when it hits a target, which can be triggered 1 time every 20s.', 'Sequence_Node_Nesting_Twigs2C_in_Beaks_They_Harrow.png', 'Nature Sings in Symphony', 'Resonance Skill DMG Bonus is increased by 40%. The Wind Field\'s pulling effect on surrounding targets is enhanced, and the pulling range is expanded by 33%.', 'Sequence_Node_Nature_Sings_in_Symphony.png', 'Close Your Eyes and Listen in', 'Mid-air Attack Feather Release\'s damage is increased by 95%.', 'Sequence_Node_Close_Your_Eyes_and_Listen_in.png', 'Winds Whisper in Harmony', 'Resonance Liberation Wind Spirals\'s damage is increased by 85%.', 'Sequence_Node_Winds_Whisper_in_Harmony.png', 'A Tribute to Life\'s Sweet Hymn', 'After casting Mid-air Attack Feather Release, the ATK of all team members is increased by 20% for 20s.', 'Sequence_Node_A_Tribute_to_Life27s_Sweet_Hymn.png', 31, 26, 25, 39, 'Resonator_Yangyang.png'),
(42, 'Yuanwu', 'Electro', 'Gauntlets', 4, 'Yuanwu in Wuthering Waves is a 4 Stars Electro character who wields a Gauntlets as their weapon type.\r\n\r\nYuanwu owns a boxing gym where he teaches Leihuangquan and health management. He is well-respected in the community for his cordial demeanor and pleasant temperament.', 'yuanwu.jpg', 'Hidden Thunder Tacet Core', 'Terraspawn Fungus', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 682, 8525, 18, 225, 134, 1637, 'Abyss Surges', 'Amity Accord', 'Stonard', 'Bell-Borne Geochelone', 'Moonlit Clouds', '• Energy Regen + 10%.\r\n• Upon using Outro Skill, increases the ATK of the next Resonator by 22.5% for 15s.', 'Crit. Rate | >60.0%', 'Crit. Rate | >230.0%', NULL, NULL, NULL, 'Leihuangquan', 'Basic Attack\r\nYuanwu performs up to 5 consecutive attacks, dealing Electro DMG.\r\nHeavy Attack\r\nYuanwu consumes STA to attack the target, dealing Electro DMG.\r\nMid-air Attack\r\nYuanwu consumes STA to launch a Mid-air Plunging Attack, dealing Electro DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Electro DMG.', 'Leihuang Master', 'Thunder Wedge\r\nYuanwu summons Thunder Wedge, dealing Electro DMG, and forms a Thunder Field centered on the Thunder Wedge. Thunder Wedge lasts for 12s. Forte Circuit Rumbling Spark and Resonance Liberation Blazing Might will immediately detonate Resonance Skill Thunder Wedge on the field, dealing Electro DMG, considered as Resonance Skill DMG.\r\nThunder Field\r\nThe active character gains the effects below when in the Thunder Field: a Coordinated Attack from Resonance Skill Thunder Wedge is triggered when attacks hit a target, dealing Electro DMG. This can be triggered once every 1.2s. The effect lasts for 1.5s.', 'Unassuming Blade', 'Rumbling Spark\r\nWhen \"Readiness\" is full, hold Resonance Skill to consume all \"Readiness\" and cast Rumbling Spark, dealing Electro DMG and entering the Lightning Infused state.\r\nThunder Uprising\r\nWhen \"Readiness\" is full, Resonance Skill Thunder Wedge will be replaced with Thunder Uprising, dealing Electro DMG.\r\nLightning Infused\r\nThe character in Lightning Infused state has a greatly increased resistance to interruption. When Yuanwu is in this state: -Basic Attacks: Hit targets in a larger range, reduce enemy Vibration Strength with increased efficiency. -Heavy Attacks: Have increased attack speed, reduce enemy Vibration Strength with increased efficiency. -Dodge Counters: Have increased attack speed, reduce enemy Vibration Strength with increased efficiency. -Use Basic Attack within 3s after casting a Heavy Attack or a successful Counterattack to cast Thunderweaver, dealing Electro DMG, considered as Basic Attack DMG. -Does not recover \"Readiness\".\r\nReadiness\r\nYuanwu can hold up to 100 \"Readiness\". When Resonance Skill Thunder Wedge is on the field, Yuanwu gains 6 \"Readiness\" every second, even when he is not the active character; When Resonance Skill Thunder Wedge hits a target with a Coordinated Attack, Yuanwu gains 5 \"Readiness\".', 'Blazing Might', 'Awaken the power of thunder and provide Forte Circuit Lightning Infused status to all characters on a nearby team for 10s, then perform a powerful blow that deals Electro DMG.', 'Thunder Bombardment', 'Attack the target, dealing Electro DMG.', 'Lightning Manipulation\r\n', 'Yuanwu unleashes thunderbolts in an area centered around the skill target, greatly reducing the Vibration Strength of enemies upon impact.', 'Thunderous Determination', 'The DMG multiplier of Resonance Skill Thunder Uprising is increased by 40%, and its reduction efficiency of enemy Vibration Strength is enhanced.', 'Reserved Confidence', 'The ranges of the Resonance Skills Thunder Field and Thunder Uprising are greatly expanded. When switched off the field during combat, if \"Readiness\" is not full, Yuanwu will automatically leave 1 Resonance Skill Thunder Wedge in place.', 'Skill_Gauntlets.png', 'Skill_Leihuang_Master.png', 'Skill_Unassuming_Blade.png', 'Skill_Blazing_Might.png', 'Skill_Thunder_Bombardment.png', 'Skill_Lightning_Manipulation.png', 'Skill_Thunderous_Determination.png', 'Skill_Reserved_Confidence.png', 'Steaming Cup of Justice', 'When Yuanwu is in Forte Circuit\'s Lightning Infused state, his Basic Attack Speed is increased by 20%, and his Heavy Attack Speed is increased by 20%.', 'Sequence_Node_Steaming_Cup_of_Justice.png', 'Fierce Heart, Serene Mind', 'Intro Skill Thunder Bombardment additionally recovers 15 Resonance Energy for Yuanwu.', 'Sequence_Node_Fierce_Heart2C_Serene_Mind.png', 'Upholder of Integrity', 'When the Coordinated Attacks of Resonance Skill\'s Thunder Wedge hits a target, the damage is additionally increased by 20% of Yuanwu\'s DEF.', 'Sequence_Node_Upholder_of_Integrity.png', 'Retributive Knuckles', 'When casting Resonance Liberation Blazing Might, the on-field character will gain a Shield equal to 200% of Yuanwu\'s DEF for 10s.', 'Sequence_Node_Retributive_Knuckles.png', 'Neighborhood Protector', 'When Resonance Skill Thunder Wedge is on the field, Yuanwu\'s Resonance Liberation DMG Bonus is increased by 50%.', 'Sequence_Node_Neighborhood_Protector.png', '\r\nDefender of All Realms', 'All team members nearby within the range of Resonance Skill Thunder Wedge will gain a 32% DEF increase, lasting 3s.', 'Sequence_Node_Defender_of_All_Realms.png', 29, 26, 25, 39, 'Resonator_Yuanwu.png'),
(43, 'Chixia', 'Fusion', 'Pistols', 4, 'Chixia in Wuthering Waves is a 4 Stars Fusion character who wields a Pistols as their weapon type.\r\n\r\nChixia is a spirited young Jinzhou Patroller who lights up the streets of Jinzhou. She\'s always ready to be the hero someone needs. She fuses such passion into the bullets that blast out of her fingertips.', 'chixia.jpg', 'Rage Tacet Core', 'Belle Poppy', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 727, 9087, 24, 300, 78, 953, 'Static Mist', 'Thunderbolt', 'Undying Flame', 'Inferno Rider', 'Molten Rift', '• Fusion DMG + 10%.\r\n• Fusion DMG + 30% for 15s after releasing Resonance Skill.', 'Crit. Rate | >66.0%', 'Crit. DMG | >269.0%', 'ATK | >2000', NULL, NULL, 'POW POW\r\n', 'Basic Attack\r\nChixia fires up to 4 consecutive shots, dealing Fusion DMG.\r\nHeavy Attack\r\nChixia enters the aiming state for a more powerful shot. The aimed shot fired after charging finishes deals Fusion DMG.\r\nMid-air Attack\r\nChixia consumes STA to perform consecutive shots at the target in mid-air, dealing Fusion DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Fusion DMG.', 'Whizzing Fight Spirit\r\n', 'Chixia unleashes a flurry of shots, dealing Fusion DMG.\r\nWhizzing Fight Spirit has 2 initial charges.', 'Heroic Bullets\r\n', 'Resonance Skill: DAKA DAKA!\r\nHold Resonance Skill Whizzing Fight Spirit to enter DAKA DAKA!. In this state: - Chixia continuously consumes \"Thermobaric Bullets\" to attack the target, dealing Fusion DMG, considered as Resonance Skill DMG. - Tap Basic Attack to cast Basic Attack 4, dealing Fusion DMG, considered as Basic Attack DMG. Then she exits the \"DAKA DAKA!\" state. - If 30 \"Thermobaric Bullets\" have been fired when Basic Attack is activated, Chixia will cast Resonance Skill Boom Boom and exit \"DAKA DAKA!\" state. - Chixia exits the \"DAKA DAKA!\" state when all \"Thermobaric Bullets\" are consumed.\r\nResonance Skill: Boom Boom\r\nDeal Fusion DMG, considered as Resonance Skill DMG.\r\nThermobaric Bullets\r\nChixia can hold up to 60 \"Thermobaric Bullets\". Inherent Skill Scorching Magazine increases Max \"Thermobaric Bullets\" by 10. Chixia obtains \"Thermobaric Bullets\" for every Normal Attack POW POW on hit. Chixia obtains \"Thermobaric Bullets\" upon casting Intro Skill Grand Entrance and Resonance Skill Whizzing Fight Spirit.', 'Blazing Flames\r\n', 'Chixia fires up fast shots at nearby enemies, dealing Fusion DMG.', 'Grand Entrance', 'Chixia makes a heroic entrance and fires rapidly with her dual pistols at the target, dealing Fusion DMG.', 'Leaping Flames\r\n', 'Chixia releases a shock wave surrounding the target, dealing Fusion DMG equal to 530.00% of Chixia\'s ATK to enemies within the range.', 'Scorching Magazine', 'Max Thermobaric Bullets is increased by 10 rounds. The damage of Resonance Skill Boom Boom is increased by 50%.', 'Numbingly Spicy!', 'Each Thermobaric Bullet that hits a target during Resonance Skill DAKA DAKA! increases ATK by 1% for 10s, stacking up to 30 times.', 'Skill_Pistols.png', 'Skill_Whizzing_Fight_Spirit.png', 'Skill_Heroic_Bullets.png', 'Skill_Blazing_Flames.png', 'Skill_Grand_Entrance.png', 'Skill_Leaping_Flames.png', 'Skill_Scorching_Magazine.png', 'Skill_Numbingly_Spicy21.png', 'No.1 Hero Play Fan', 'Resonance Skill Boom Boom hits will always be Critical Hits.', 'Sequence_Node_No.1_Hero_Play_Fan.png', 'Leaping Sparkles', 'During Resonance Liberation Blazing Flames, for every 1 target defeated, Chixia recovers 5 Resonance Energy, up to 20 each time.', 'Sequence_Node_Leaping_Sparkles.png', 'Eternal Flames', 'Resonance Liberation Blazing Flames deals 40% more DMG to targets whose HP is below 50%.', 'Sequence_Node_Eternal_Flames.png', 'Hero’s Ultimate Move', 'Resonance Liberation Blazing Flames grants 60 \"Thermobaric Bullets\" and immediately resets the Cooldown of Resonance Skill Whizzing Fight Spirit.\r\n', 'Sequence_Node_Hero3Fs_Ultimate_Move.png', 'Triumphant Explosions', 'When the Inherent Skill Numbingly Spicy! reaches max stacks, ATK is additionally increased by 30%.', 'Sequence_Node_Triumphant_Explosions.png', 'Easter Egg Performance', 'Resonance Skill Boom Boom increases the Basic Attack DMG Bonus of all team members by 25% for 15s.', 'Sequence_Node_Easter_Egg_Performance.png', 28, 48, 25, 39, 'Resonator_Chixia.png'),
(44, 'Mortefi', 'Fusion', 'Pistols', 4, 'Mortefi in Wuthering Waves is a 4 Stars Fusion character who wields a Pistols as their weapon type.\r\n\r\nMortefi, a skilled expert in Applied Tacetite Study and a member of the Academy’s Department of Safety, possesses the unique ability to transform his accumulated frustration into fiery flames. From a burning wrath that consumes all, the red dragon shall descend.', 'mortefi.jpg', 'Rage Tacet Core', 'Coriolus', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 802, 10025, 20, 250, 93, 1136, 'Static Mist', 'Cadenza', 'Relativistic Jet', 'Impermanence Heron', 'Moonlit Clouds', '• Energy Regen + 10%.\r\n• Upon using Outro Skill, increases the ATK of the next Resonator by 22.5% for 15s.', 'Crit. Rate | >65.0%', 'Crit. DMG | >250.0%', 'Resonance Skill DMG Bonus | >20.0%', NULL, NULL, 'Impromptu Show', 'Basic Attack\r\nMortefi uses his dual pistols and flames to perform up to 4 consecutive shots, dealing Fusion DMG.\r\nHeavy Attack\r\nMortefi enters the aiming state for a more powerful shot. The aimed shot fired after charging finishes deals Fusion DMG.\r\nMid-air Attack\r\nMortefi consumes STA to perform consecutive shots at the target in mid-air, dealing Fusion DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Fusion DMG.\r\n\r\n', 'Passionate Variation\r\n', 'Launch a flashing lightning of flames forward, dealing Fusion DMG.', 'Fury Fugue', 'Resonance Skill: Fury Fugue\r\nWhen Mortefi\'s Annoyance reaches 100, his Resonance Skill is replaced with Fury Fugue. When casting Fury Fugue, Mortefi consumes all Annoyance to unleash high-speed flame lightning, dealing Fusion DMG, considered as Resonance Skill DMG.\r\nAnnoyance\r\nMortefi can hold up to 100 Annoyance and can restore Annoyance in the following ways: - When Normal Attack Impromptu Show hits the target - When Intro Skill Dissonance hits the target - When Resonance Skill Passionate Variation hits the target - Within 5s after casting Passionate Variation, Normal Attack Impromptu Show that hits the target restores Annoyance additionally.', 'Violent Finale', 'Deal Fusion DMG, and apply Burning Rhapsody to all characters on the team.\r\nBurning Rhapsody\r\nWhen the active character\'s Basic Attack hits the target, Mortefi launches a Coordinated Attack, firing 1 Marcato. When the active character\'s Heavy Attack hits the target, Mortefi launches a Coordinated Attack, firing 2 Marcato. Mortefi can launch one Coordinated Attack every 0.35s.\r\nMarcato\r\nDeals Fusion DMG.', 'Dissonance', 'Attack the target, dealing Fusion DMG.\r\n\r\n', 'Rage Transposition\r\n', 'The incoming Resonator gains 38% Heavy Attack DMG Amplification for 14s or until they are switched out.', 'Harmonic Control', 'After casting Resonance Skill Passionate Variation, the damage of Resonance Skill Fury Fugue is increased by 25% for 8s.\r\n\r\n', 'Rhythmic Vibrato\r\n', 'During Resonance Liberation Burning Rhapsody, each hit of Resonance Liberation Marcato will increase the DMG of the next Resonance Liberation Marcato by 1.5%, which can be triggered once every 0.35s, stacking up to 50 times. The effect will be reset after Resonance Liberation Burning Rhapsody ends.\r\n\r\n', 'Skill_Pistols.png', 'Skill_Passionate_Variation.png', 'Skill_Fury_Fugue.png', 'Skill_Violent_Finale.png', 'Skill_Dissonance.png', 'Skill_Rage_Transposition.png', 'Skill_Harmonic_Control.png', 'Skill_Rhythmic_Vibrato.png', 'Solitary Etude', 'During Resonance Liberation Burning Rhapsody, Mortefi launches Coordinated Attacks when the on-field character performs their Resonance Skills, firing 2 Resonance Liberation\'s Marcato hits, dealing Fusion DMG.', 'Sequence_Node_Solitary_Etude.png', 'Hypocritical Hymn', 'After using the Echo Skill, Mortefi restores an additional 10 Resonance Energy. This can be triggered once every 20 second.', 'Sequence_Node_Hypocritical_Hymn.png', 'Flaming Recitativo', 'During Resonance Liberation Burning Rhapsody, the Crit. DMG of Resonance Liberation\'s Marcato is increased by 30%.', 'Sequence_Node_Flaming_Recitativo.png', 'Cathartic Waltz', 'The duration of Resonance Liberation Burning Rhapsody is extended by 7s.', 'Sequence_Node_Cathartic_Waltz.png', 'Funerary Quartet', 'When Resonance Skill Passionate Variation or Resonance Skill Fury Fugue hits a target, Coordinated Attacks will be triggered to fire 4 Resonance Liberation\'s Marcato hit(s), dealing Fusion Damage. DMG of Resonance Liberation\'s Marcato fired in this way is reduced by 50%.', 'Sequence_Node_Funerary_Quartet.png', 'Apoplectic Instrumental', 'When Resonance Liberation Violent Finale is cast, ATK of all team members is increased by 20% for 20s.', 'Sequence_Node_Apoplectic_Instrumental.png', 31, 29, 25, 39, 'Resonator_Mortefi.png'),
(45, 'Sanhua', 'Glacio', 'Sword', 4, 'Sanhua in Wuthering Waves is a 4 Stars Glacio character who wields a Sword as their weapon type.\r\n\r\nThe bodyguard of Jinzhou\'s Magistrate, known for having an icy personality. Once regarded as the Asura of Calamity, Sanhua is now a taciturn guardian. She has learned to maintain inner calmness amidst the chaotic frequencies, and the things that once frightened her now fuel her determination.', 'sanhua.jpg', 'Sound-Keeping Tacet Core', 'Wintry Bell', 'LF Whisperin Core', 'MF Whisperin Core', 'HF Whisperin Core', 'FF Whisperin Core', 805, 10062, 22, 275, 77, 941, 'Emerald of Genesis', 'Overture', 'Commando of Conviction', 'Impermanence Heron', 'Moonlit Clouds', '• Energy Regen + 10%.\r\n• Upon using Outro Skill, increases the ATK of the next Resonator by 22.5% for 15s.', 'Crit. Rate | >60.0%', 'Crit. DMG | >200.0%', 'Energy Regen | >150.0%', NULL, NULL, 'Frigid Light', 'Basic Attack\r\nSanhua performs up to 5 consecutive attacks, dealing Glacio DMG.\r\nHeavy Attack\r\nSanhua consumes STA to launch attacks, dealing Glacio DMG.\r\nMid-air Attack\r\nSanhua consumes STA to perform a Mid-Air Plunging Attack, dealing Glacio DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Glacio DMG.', 'Eternal Frost', 'Sanhua sends an air blade to create 1 Ice Prism on the ground, dealing Glacio DMG.', 'Clarity of Mind', 'Heavy Attack: Detonate\r\nWhen holding Basic Attack, a cursor moves back and forth on the Forte Gauge. Release Basic Attack while cursor falls in the \"Frostbite\" area, to perform Heavy Attack Detonate, dealing Glacio DMG considered as Heavy Attack DMG.\r\nIce Burst\r\nSanhua\'s Heavy Attack Detonate detonates all \"Ice Thorns\", \"Ice Prisms\" and \"Glaciers\" within her attack range, dealing Glacio DMG. Ice Burst deals Resonance Skill DMG.\r\nFrostbite Area\r\nThe \"Frostbite\" area expands with every 1 stack of \"Clarity\". \"Clarity\" stacks up to 2 times. Sanhua obtains 1 stack of \"Clarity\" upon performing Basic Attack 5. Sanhua obtains 1 stack of \"Clarity\" upon casting Intro Skill Freezing Thorns. Sanhua obtains 1 stack of \"Clarity\" upon casting Resonance Skill Eternal Frost. Sanhua obtains 2 stack(s) of \"Clarity\" upon casting Resonance Liberation Glacial Gaze. Upon casting Heavy Attack Detonate, all \"Clarity\" is removed.', 'Glacial Gaze', 'Sanhua deals Glacio DMG and creates 1 Glacier.', 'Freezing Thorns', 'Sanhua swings her blade downward and creates 1 Ice Thorn, dealing Glacio DMG.', 'Silversnow', 'The incoming Resonator has their Basic Attack DMG Amplified by 38% for 14s or until they are switched out.', 'Condensation', 'Damage dealt by Sanhua\'s Resonance Skill increased by 20% for 8s after casting her Intro Skill.', 'Avalanche', 'Damage dealt by Sanhua\'s Forte Circuit Ice Burst is increased by 20% for 8s after casting Basic Attack 5.', 'Skill_Sword.png', 'Skill_Eternal_Frost.png', 'Skill_Clarity_of_Mind.png', 'Skill_Glacial_Gaze.png', 'Skill_Freezing_Thorns.png', 'Skill_Silversnow.png', 'Skill_Condensation.png', 'Skill_Avalanche.png', 'Solitude\'s Embrace', 'Basic Attack V increases Sanhua\'s Crit. Rate by 15% for 10s.', 'Sequence_Node_Solitude27s_Embrace.png', 'Snowy Clarity', 'Heavy Attack Detonate STA cost is reduced by 10. When Sanhua casts Resonance Skill Eternal Frost, her resistance to interruption is enhanced for 10s.', 'Sequence_Node_Snowy_Clarity.png', 'Anomalous Vision', 'Sanhua\'s damage dealt is increased by 35% against targets with HP below 70%.', 'Sequence_Node_Anomalous_Vision.png', 'Blade Mastery', 'Resonance Liberation Glacial Gaze restores 10 Resonance Energy. DMG of the next Heavy Attack Detonate within 5s is increased by 120%.', 'Sequence_Node_Blade_Mastery.png', 'Unraveling Fate', 'Crit. DMG of Forte Circuit Ice Burst is increased by 100%. Ice Creations (Ice Thorn, Ice Prism, and Glacier) will explode even if they are not detonated.', 'Sequence_Node_Unraveling_Fate.png', 'Daybreak Radiance', 'After an Ice Prism or a Glacier is detonated, all team members\' ATK is increased by 10% for 20s, stacking up to 2 times.', 'Sequence_Node_Daybreak_Radiance.png', 23, 37, 25, 39, 'Resonator_Sanhua.png'),
(46, 'Baizhi', 'Glacio', 'Rectifier', 4, 'Baizhi in Wuthering Waves is a 4 Stars Glacio character who wields a Rectifier as their weapon type.\r\n\r\nBaizhi is a researcher in Remnant Ecoacoustics. Baizhi\'s once unfulfilled wish has now manifested as her loyal companion. The Remnant Creature You\'tan is her source of healing powers, and a lifelong research focus.', 'baizhi.jpg', 'Sound-Keeping Tacet Core', 'Lanternberry', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 1025, 12812, 17, 212, 82, 1002, 'Stellar Symphony', 'Variation', 'Comet Flare', 'Bell-Borne Geochelone', 'Rejuvenating Glow', '• Healing Bonus + 10%.\r\n• Increases the ATK of all party members by 15% for 30s upon healing allies.', 'Energy Regen | >220.0%', 'HP | >23000', NULL, NULL, NULL, 'Destined Promise', 'Basic Attack\r\nBaizhi instructs You\'tan to perform up to 4 consecutive attacks, dealing Glacio DMG.\r\nHeavy Attack\r\nBaizhi continuously consumes STA to command You\'tan to attack enemies, dealing Glacio DMG. During Heavy Attack, Baizhi can command You\'tan to move.\r\nMid-air Attack\r\nBaizhi consumes STA and summons You\'tan in mid-air to perform a Plunging Attack, dealing Glacio DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Glacio DMG.', 'Emergency Plan\r\n', 'Baizhi calls You\'tan to attack the target, dealing Glacio DMG while immediately healing all characters on nearby teams.', 'Cycle of Life', 'You\'tan\r\nA Remnant Creature that answers to Baizhi\'s mind and desires while sharing all her stats. You\'tan goes back to Baizhi when Baizhi dodges.\r\nConcentration\r\nBaizhi consumes all \"Concentration\" when casting Heavy Attack or Resonance Skill Emergency Plan to continuously heal all Resonators on nearby teams. Each 1 \"Concentration\" consumed provides 1 healing. The healing happens every 2s. When Baizhi consumes \"Concentration\" to cast Heavy Attack, Baizhi additionally restores Concerto Energy and Resonance Energy. When Baizhi consumes \"Concentration\" to cast Resonance Skill Emergency Plan, Baizhi additionally restores Concerto Energy.\r\nForte Gauge: Concentration\r\nBaizhi can hold up to 4 \"Concentration\". Baizhi obtains 1 \"Concentration\" for every Basic Attack on hit.', 'Momentary Union', 'Baizhi summons You\'tan to heal all characters on nearby teams, generating 4 stacks of Remnant Entities.\r\nRemnant Entities\r\nRemnant Entities follow the active team members. 1 stack(s) of Remnant Entities are automatically consumed to perform Coordinated Attacks every 2.5s, dealing Glacio DMG on hit while healing all characters of the team when the active character is within the range.', 'Overflowing Frost\r\n', 'Baizhi calls You\'tan to perform 1 plunging attack, dealing Glacio DMG while healing all characters on a nearby team.', 'Rejuvinating Flow', 'Heal the incoming Resonator by 1.54% of Baizhi\'s max HP every 3s for 30s. The healed Resonator has their DMG Amplified by 15% for 6s.', 'Harmonic Range', 'When Baizhi casts Resonance Skill Emergency Plan, You\'tan generates a field of Euphonia that lasts for 15s.\r\nEuphonia\r\nATK of the Resonators who pick up Euphonia is increased by 15% for 20s.', 'Stimulus Feedback', 'Baizhi\'s Heavy Attack on hit heals the character with the lowest HP on a nearby team by 0.25% of her Max HP.', 'Skill_Rectifier.png', 'Skill_Emergency_Plan.png', 'Skill_Cycle_of_Life.png', 'Skill_Momentary_Union.png', 'Skill_Overflowing_Frost.png', 'Skill_Rejuvinating_Flow.png', 'Skill_Harmonic_Range.png', 'Skill_Stimulus_Feedback.png', 'Complex Simplicity', 'Resonance Skill Emergency Plan additionally restores 2.5 Resonance Energy for every 1 Concentration consumed.', 'Sequence_Node_Complex_Simplicity.png', 'Silent Tundra', 'Resonance Skill Emergency Plan increases Baizhi\'s Glacio DMG Bonus by 15% and her Healing by 15% if she has 4 Concentration. These effects last for 12s.', 'Sequence_Node_Silent_Tundra.png', 'Veritas Lux Mea', 'Intro Skill Overflowing Frost increases Baizhi\'s Max HP by 12% for 10s.\r\n', 'Sequence_Node_Veritas_Lux_Mea.png', 'Eternal Verity\r\n', 'Upon casting Resonance Liberation Momentary Union, Resonance Liberation Remnant Entities gains the following enhancements: -Remnant Entities can be performed 2 more time(s); -Healing multiplier of Remnant Entities is increased by 20%; -Remnant Entities deals additional Glacio DMG equal to 1.20% of Baizhi\'s Max HP.', 'Sequence_Node_Eternal_Verity.png', 'A Wish Answered', 'If a team member is knocked out when Baizhi is alive on the team, immediately revive them and restore 100% of their Max HP. This effect can be triggered once every 10 minute(s).', 'Sequence_Node_A_Wish_Answered.png', 'Seeker\'s Devotion', 'When Euphonia is picked up, increase the Glacio DMG Bonus of all characters nearby by 12% for 20s.', 'Sequence_Node_Seeker27s_Devotion.png', 23, 31, 45, 44, 'Resonator_Baizhi.png'),
(47, 'Danjin', 'Havoc', 'Sword', 4, 'Danjin in Wuthering Waves is a 4 Stars Havoc character who wields a Sword as their weapon type.\r\n\r\nWith a vengeful blade of condensed blood in hand, Ranger Danjin hunts down thieves and bandits for retribution. She journeys to distant lands in pursuit of justice.', 'danjin.jpg', 'Strife Tacet Core', 'Belle Poppy', 'Crude Ring', 'Basic Ring', 'Improved Ring', 'Tailored Ring', 755, 9437, 21, 262, 94, 1148, 'Blazing Brilliance', 'Red Spring', 'Emerald of Genesis', 'Dreamless', 'Havoc Eclipse', '• Havoc DMG + 10%.\r\n• Havoc DMG + 7.5% after releasing Basic Attack or Heavy Attack. This effect stacks up to 4 times, each stack lasts 15s.', 'Crit. Rate | >60.0%', 'Crit. DMG | >260.0%', NULL, NULL, NULL, 'Execution', 'Basic Attack\r\nDanjin performs up to 3 consecutive attacks, dealing Havoc DMG.\r\nHeavy Attack\r\nDanjin consumes STA to launch consecutive attacks, dealing Havoc DMG.\r\nMid-air Attack\r\nConsume STA to perform a Mid-air Plunging Attack, dealing Havoc DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to launch an attack, dealing Havoc DMG.\r\nDodge Counter: Ruby Shades\r\nAfter a successful Dodge Counter, Danjin can use Resonance Skill Crimson Fragment to perform Resonance Skill: Crimson Erosion.\r\n\r\n', 'Crimson Fragment\r\n', 'When casting Crimson Fragment, each attack consumes 3% of Danjin\'s max HP. When Danjin\'s HP is less than 1%, this no longer consumes HP.\r\nCarmine Gleam\r\nDanjin attacks the target, dealing Havoc DMG.\r\nCrimson Erosion\r\nAfter Basic Attack 2, Dodge Counter or Intro Skill Vindication, use Resonance Skill to perform up to 2 consecutive strikes, dealing Havoc DMG. When Crimson Erosion 2 hits a target, apply Incinerating Will to it.\r\nIncinerating Will\r\nDanjin\'s damage dealt to targets marked with Incinerating Will is increased by 20%.\r\nSanguine Pulse\r\nUse Resonance Skill after Basic Attack 3 to perform up to 3 consecutive attacks, dealing Havoc DMG.', 'Serene Vigil', 'Heavy Attack: Chaoscleave\r\nAfter accumulating 60 \"Ruby Blossom\", long press Basic Attack to consume all \"Ruby Blossom\" to cast Chaoscleave, dealing Havoc DMG, considered as Heavy Attack DMG, and healing Danjin. If current \"Ruby Blossom\" reaches over 120, 120 \"Ruby Blossom\" is consumed instead to increase the DMG multiplier of Chaoscleave and Scatterbloom performed this time.\r\nHeavy Attack: Scatterbloom\r\nUse Basic Attack after Heavy Attack Chaoscleave to cast Scatterbloom to attack the target, dealing Havoc DMG, considered as Heavy Attack DMG.\r\nRuby Blossom\r\nDanjin can hold up to 120 Ruby Blossom. Danjin obtains \"Ruby Blossom\" when using Resonance Skill Crimson Fragment.', 'Crimson Bloom', 'Danjin\'s anger intensifies as she frantically swings her dual blades, performing multiple rapid consecutive attacks, and 1 Scarlet Burst attack(s), dealing Havoc DMG.', 'Vindication', 'With unwavering determination, Danjin unleashes a strike, dealing Havoc DMG.', 'Duality\r\n', 'The incoming Resonator has their Havoc DMG Amplified by 23% for 14s or until they are switched out.', 'Crimson Light', 'Damage of Resonance Skill Crimson Erosion triggered by Dodge Counter: Ruby Shades is increased by 20%. The HP cost and stacks of Ruby Blossom recovered are doubled.', 'Overflow', 'After casting the Resonance Skill Sanguine Pulse, Danjin\'s Heavy Attack DMG is increased by 30% for 5s.', 'Skill_Sword.png', 'Skill_Crimson_Fragment.png', 'Skill_Serene_Vigil.png', 'Skill_Crimson_Bloom.png', 'Skill_Vindication.png', 'Skill_Duality.png', 'Skill_Crimson_Light.png', 'Skill_Overflow.png', 'Crimson Heart of Justice', 'When Danjin attacks a target with Resonance Skill\'s Incinerating Will, her ATK is increased by 5% for 6s, stacking up to 6 times. Danjin loses 1 stacks of this effect each time she takes damage.', 'Sequence_Node_Crimson_Heart_of_Justice.png', 'Dusted Mirror', 'When Danjin attacks a target with Resonance Skill\'s Incinerating Will, her damage dealt is increased by 20%.', 'Sequence_Node_Dusted_Mirror.png', 'Fleeting Blossom', 'Resonance Liberation DMG Bonus is increased by 30%.', 'Sequence_Node_Fleeting_Blossom.png', 'Solitary Carnation', 'When Danjin has more than 60 \"Ruby Blossom\", her Crit. Rate is increased by 15%. This effect lasts until the end of Heavy Attack: Scatterbloom even after all \"Ruby Blossom\" is consumed when casting Heavy Attack: Chaoscleave.', 'Sequence_Node_Solitary_Carnation.png', 'Reigning Blade', 'Danjin\'s Havoc DMG Bonus is increased by 15%, and further increased by another 15% when her HP is lower than 60%.', 'Sequence_Node_Reigning_Blade.png', 'Bloodied Jade', 'Heavy Attack Chaoscleave increases the ATK of all team members by 20% for 20s.', 'Sequence_Node_Bloodied_Jade.png', 44, 45, 25, 39, 'Resonator_Danjin.png'),
(48, 'Taoqi', 'Havoc', 'Broadblade', 4, 'Taoqi in Wuthering Waves is a 4 Stars Havoc character who wields a Broadblade as their weapon type.\r\n\r\nTaoqi is the director of border defense at the Ministry of Development. Despite her seemingly laid-back demeanor, she consistently proves to be a dependable and supportive individual, always lending her hand to those in need. Taoqi is not only a reliable colleague, but also a trustworthy friend that people can confide in.', 'taoqi.jpg', 'Gold-Dissolving Feather', 'Iris', 'LF Howler Core', 'MF Howler Core', 'HF Howler Core', 'FF Howler Core', 716, 8950, 18, 225, 128, 1564, 'Dauntless Evernight', 'Discord', 'Autumntrace', 'Bell-Borne Geochelone', 'Moonlit Clouds', '• Energy Regen + 10%.\r\n• Upon using Outro Skill, increases the ATK of the next Resonator by 22.5% for 15s.', 'DEF | >4000', NULL, NULL, NULL, NULL, 'Concealed Edge', 'Basic Attack\r\nPerform up to 4 consecutive attacks, dealing Havoc DMG.\r\nHeavy Attack\r\nConsume Stamina to deal Havoc DMG. Hold Basic Attack to enter Rocksteady Defense.\r\nRocksteady Defense\r\n- Taoqi\'s damage taken is reduced by 35%; - When Taoqi is attacked during Rocksteady Defense, she will cast Strategic Parry; - Strategic Parry is automatically cast after Rocksteady Defense lasts for 3s; If Taoqi is attacked when casting Resonance Skill Fortified Defense, Strategic Parry is automatically cast.\r\nStrategic Parry\r\nAttack the target, dealing Havoc DMG.\r\nMid-Air Attack\r\nConsume Stamina to perform a Plunging Attack while in mid-air, dealing Havoc DMG.\r\nDodge Counter\r\nUse Basic Attack after a successful Dodge to attack the target, dealing Havoc DMG.', 'Fortified Defense', 'Taoqi deals Havoc DMG to surrounding targets, generating 3 Rocksteady Shield and healing herself. If attacked when casting Fortified Defense, Strategic Parry will be automatically cast.\r\nRocksteady Shield\r\nWhen the active character on the team is attacked, 1 Rocksteady Shield is consumed to reduce the damage taken.', 'Power Shift', 'Timed Counters\r\nWhen carrying \"Resolving Caliber\", use Basic Attack after Heavy Attack Strategic Parry or Intro Skill Defense Formation to cast Timed Counters, performing up to 3 consecutive attacks, dealing Havoc DMG, considered as Basic Attack DMG. Timed Counters consume 1 \"Resolving Caliber\" upon hitting an enemy to grant a shield. After casting the Intro Skill Defense Formation, use Basic Attack to directly cast Timed Counters.\r\nResolving Caliber\r\nTaoqi can hold up to 3 Resolving Caliber. Basic Attack 4 will consume all of Taoqi\'s \"Rocksteady Shields\" to grant that many \"Resolving Caliber\". While Rocksteady Shield exists, when the active character is attacked, 1 \"Rocksteady Shield\" will be consumed to recover \"Resolving Caliber\". After Rocksteady Shield ends, all remaining \"Rocksteady Shield\" will be consumed to grant that many \"Resolving Caliber\".', 'Unmovable', 'Attack the target based on Taoqi\'s DEF, dealing Havoc DMG.', 'Defense Formation', 'Attack the target, dealing Havoc DMG.', 'Iron Will', 'The incoming Resonator has their Resonance Skill DMG Amplified by 38% for 14s or until they are switched out.', 'Steadfast Protection', 'While Resonance Skill Rocksteady Shield lasts, the Character\'s DEF is increased by 15%.', 'Unyielding', 'After Heavy Attack Strategic Parry is successfully triggered, 25 STA is recovered.', 'Skill_Broadblade.png', 'Skill_Fortified_Defense.png', 'Skill_Power_Shift.png', 'Skill_Unmovable.png', 'Skill_Defense_Formation.png', 'Skill_Iron_Will.png', 'Skill_Steadfast_Protection.png', 'Skill_Unyielding.png', 'Essense of Tranquility', 'Forte Circuit Power Shift\'s Shield is increased by 40%.', 'Sequence_Node_Essense_of_Tranquility.png', 'Silent Strength', 'The Crit. Rate and Crit. DMG of Resonance Liberation Unmovable is increased by 20% and 20%, respectively.\r\n', 'Sequence_Node_Silent_Strength.png', 'Keen-eyed Observer', 'The duration of Resonance Skill Rocksteady Shield is extended to 30s.', 'Sequence_Node_Keen-eyed_Observer.png', 'Heavylifting Duty', 'When Taoqi successfully triggers Heavy Attack Strategic Parry, she restores 25% HP and increases her DEF by 50% for 5s. This can be triggered once every 15s.', 'Sequence_Node_Heavylifting_Duty.png', 'Benevolent Guardian', 'The damage of Forte Circuit Power Shift is increased by 50%. When Forte Circuit Power Shift hits a target, restore 20 Resonance Energy.', 'Sequence_Node_Benevolent_Guardian.png', 'Defender of Peace\r\n', 'The damage of Taoqi\'s Basic Attack and Heavy Attack is increased by 40% while the Shield granted by Resonance Skill Rocksteady Shield holds.', 'Sequence_Node_Defender_of_Peace.png', 29, 47, 25, 39, 'Resonator_Taoqi.png');

-- --------------------------------------------------------

--
-- Table structure for table `echoes`
--

CREATE TABLE `echoes` (
  `id` int(11) NOT NULL,
  `name` varchar(150) NOT NULL,
  `cost` int(11) NOT NULL,
  `sonata_effect` varchar(255) DEFAULT 'Various',
  `image_url` varchar(255) DEFAULT 'default_echo.jpg',
  `description` text DEFAULT NULL
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;

--
-- Dumping data for table `echoes`
--

INSERT INTO `echoes` (`id`, `name`, `cost`, `sonata_effect`, `image_url`, `description`) VALUES
(7, 'Lampylumen Myriad', 4, 'Freezing Frost', 'Lampylumen_Myriad.jpg', 'Transform into Lampylumen Myriad. Perform up to 3 consecutive attacks. Unleash a freezing shock by performing consecutive forward strikes, with the initial two strikes inflicting 200.16% and 200.16% Glacio DMG respectively, and the final strike dealing 266.88% Glacio DMG. Enemies will be frozen on hit. Each shock increases the current character\'s Glacio DMG by 4.00% and Resonance Skill DMG dealt by 4.00% for 15s, stacking up to 3 times \r\n\r\nCD: 20s'),
(12, 'Bell-Borne Geochelone', 4, 'Moonlit Clouds, Rejuvenating Glow', 'Bell-Borne Geochelone.jpg', 'Activate the protection of Bell-Borne Geochelone. Deal Glacio DMG based on 145.92% of the current character\'s DEF to nearby enemies, and obtain a Bell-Borne Shield that lasts for 15s The Bell-Borne Shield provides 50.00% DMG Reduction and 10.00% DMG Boost for the current team members, and disappears after the current character is hit for 3 times. \r\n\r\nCD: 20s'),
(14, 'Mech Abomination', 4, 'Lingering Tunes', 'Mech_Abomination.jpg', 'Strike enemies in front, dealing 48.64% Electro DMG, and summon Mech Waste to attack. Mech Waste deals 320.00% Electro DMG on hit and explodes after a while, dealing 160.00% Electro DMG. After casting this Echo Skill, increase the current character\'s ATK by 12.00% for 15s. Damage dealt by Mech Waste equals to the Resonator\'s Outro Skill DMG. \r\n\r\nCD: 20s'),
(17, 'Tempest Mephis', 4, 'Void Thunder', 'Tempest_Mephis.jpg', 'Transform into Tempest Mephis to perform tail swing attacks followed by a claw attack. The lightning strike summoned by the tail swing deals 102.48% Electro DMG each time, while the claw attack deals 175.68% Electro DMG. After the claw hit, increase the current character\'s Electro DMG by 12.00% and Heavy Attack DMG by 12.00% for 15s. \r\n\r\nCD: 20s'),
(34, 'Jué', 4, 'Celestial Light', 'Jue.jpg', 'Summon Jué to the aid. Jué soars through the air, dealing 48.64% Spectro DMG, and summons thunderbolts that strike nearby enemies up to 5 times, each hit dealing 19.46% Spectro DMG. Jué then spirals downward, attacking surrounding enemies twice, each hit dealing 48.64% Spectro DMG. Casting this Echo Skill grants the Resonator a Blessing of Time effect that lasts 15s, during when: - The Resonator gains 16.00% Resonance Skill DMG Bonus. - When the Resonator\'s Resonance Skill hits the target, inflict 16.00% Spectro DMG 1 time per second for 15s, considered as the Resonator\'s Resonance Skill DMG. \r\n\r\nCD: 20s'),
(41, 'Autopuppet Scout', 3, 'Celestial Light, Freezing Frost', 'Autopuppet_Scout.jpg', 'Transform into Autopuppet Scout, dealing 272.00% Glacio DMG to the surroundings, and generate up to 3 Ice Walls to block off the enemies. \r\n\r\nCD: 15s'),
(43, 'Carapace', 3, 'Moonlit Clouds, Sierra Gale', 'Carapace.jpg', 'Transform into Carapace to perform a spinning attack that deals 112.00% Aero DMG, followed by a slash that deals 168.00% Aero DMG. \r\n\r\nCD: 15s'),
(44, 'Chasm Guardian', 3, 'Lingering Tunes, Rejuvenating Glow', 'Chasm_Guardian.jpg', 'Transform into Chasm Guardian to perform a Leap Strike that deals 273.60% Havoc DMG on hit. Current character loses 10.00% HP after the hit lands. Periodically restore current character\'s HP after 5s for up to 10.00% of their Max HP. \r\n\r\nCD: 15s'),
(48, 'Cyan-Feathered Heron', 3, 'Sierra Gale, Celestial Light', 'Cyan-Feathered_Heron.jpg', 'Transform into Cyan-Feathered Heron and charge at the enemies, dealing 236.80% Aero DMG; This Echo Skill interrupts enemy Special Skills upon dealing damage. \r\n\r\nCD: 15s'),
(50, 'Flautist', 3, 'Lingering Tunes, Void Thunder', 'Flautist.jpg', 'Transform into Flautist, continuously emitting Electro lasers, dealing 53.28% Electro DMG for a total of 10 times. Gain 1 Concerto Energy every time a hit lands. \r\n\r\nCD: 15s'),
(53, 'Glacio Dreadmane', 3, 'Moonlit Clouds, Freezing Frost', 'Glacio_Dreadmane.jpg', 'Lacerate enemies as a Glacio Dreadmane, dealing 214.40% Glacio DMG on each hit. Equipped with 2 charges and can be cast mid-air. Glacio Dreadmane deals 20.00% more DMG while in mid-air and generates 6 Icicles upon landing, each dealing 32.00% Glacio DMG. \r\n\r\nCD: 20s'),
(55, 'Havoc Dreadmane', 3, 'Molten Rift, Havoc Eclipse', 'Havoc_Dreadmane.jpg', 'Transform into a Havoc Dreadmane to perform up to 2 tail strikes. Each strike deals 116.64% Havoc DMG and inflicts an additional instance of 77.76% Havoc DMG upon hitting the target. \r\n\r\nCD: 15s'),
(56, 'Hoochief', 3, 'Rejuvenating Glow, Sierra Gale', 'Hoochief_Cyclone.jpg', 'Transform into Hoochief and smack the enemies, dealing 268.20% Aero DMG. \r\n\r\nCD: 15s'),
(74, 'Rocksteady Guardian', 3, 'Rejuvenating Glow, Celestial Light', 'Rocksteady_Guardian.jpg', 'Transform into Rocksteady Guardian and enter a Parry State. Upon being attacked, deal Spectro DMG equal to 8.29% of the Resonator\'s Max HP, and perform a follow-up attack that deals Spectro DMG equal to 8.29% of the Resonator\'s Max HP. Use the Echo Skill again to exit the transformation. If the attack received is a Special Skill attack, interrupt the enemy\'s Special Skill, gain a Shield equal to 30% Max HP, and perform a two-stage follow-up attack, each dealing Spectro DMG equal to 5.52% of the Resonator\'s Max HP. These follow-up attacks simultaneously launch three ground-breaking waves, each dealing Spectro DMG equal to 4.59% of the Resonator\'s Max HP. \r\n\r\nCD: 15s'),
(75, 'Roseshroom', 3, 'Freezing Frost, Havoc Eclipse', 'Roseshroom.jpg', 'Summon a Roseshroom that fires a laser, dealing 57.07% Havoc DMG up to 3 times. \r\n\r\nCD: 15s'),
(79, 'Spearback', 3, 'Lingering Tunes, Moonlit Clouds', 'Spearback.jpg', 'Summon a Spearback to perform 5 consecutive attacks. The first 4 attacks deal 29.96% Physical DMG, and the last deals 51.36% Physical DMG. \r\n\r\nCD: 15s'),
(80, 'Stonewall Bracer', 3, 'Rejuvenating Glow, Moonlit Clouds', 'Stonewall_Bracer.jpg', 'Transform into Stonewall Bracer and charge forward, dealing 112.64% Physical DMG on-hit, then smash to deal 168.96% Physical DMG, and gain a shield of 10.00% of current character\'s Max HP that lasts 7s. Use the Echo skill again to exit the transformation state. \r\n\r\nCD: 15s'),
(81, 'Tambourinist', 3, 'Freezing Frost, Havoc Eclipse', 'Tambourinist.jpg', 'Summon a Tambourinist that plays out Melodies of Annihilation. Any Resonator on the team gains the following effect for 10s upon obtaining a Melody of Annihilation: When the Resonator hits a target, the Tambourinist deals 14.40% Havoc DMG to the target, up to 10 times. \r\n\r\nCD: 15s'),
(84, 'Violet-Feathered Heron', 3, 'Molten Rift, Void Thunder', 'Violet-Feathered_Heron.jpg', 'Transform into Violet-Feathered Heron and enter a Parry Stance. Counterattack when the Parry stance is over, dealing 288.00% Electro DMG. If attacked during Parry Stance, you can counterattack in advance and additionally recover 5 Concerto Energy. \r\n\r\nCD: 15s'),
(85, 'Viridblaze Saurian', 3, 'Moonlit Clouds, Molten Rift', 'Viridblaze_Saurian.jpg', 'Summon a Viridblaze Saurian to continuously spit fire, dealing 17.12% Fusion DMG 10 times. \r\n\r\nCD: 15s'),
(89, 'Aero Predator', 1, 'Void Thunder, Sierra Gale', 'Aero_Predator.jpg', 'Summon an Aero Predator that throws a dart forward. The dart will bounce between enemies up to three times, dealing 28.80% Aero DMG each time it hits. \r\n\r\nCD: 8s'),
(91, 'Baby Viridblaze Saurian', 1, 'Lingering Tunes, Void Thunder, Molten Rift\r\n', 'Baby_Viridblaze_Saurian.jpg', 'Transform into Baby Viridblaze Saurian to rest in place, and slowly restore HP. \r\n\r\nCD: 8s'),
(94, 'Chirpuff', 1, 'Havoc Eclipse, Sierra Gale', 'Chirpuff.jpg', 'Summon a Chirpuff that self-inflates and blasts a powerful gust of wind forward 3 times. Each blast inflicts 38.40% Aero DMG and pushes enemies backwards. \r\n\r\nCD: 8s'),
(98, 'Clang Bang', 1, 'Celestial Light, Freezing Frost', 'Clang_Bang.jpg', 'Summon a Clang Bang that follows the enemy and eventually self-combusts, dealing 32.00%+64 Glacio DMG. \r\n\r\nCD: 8s'),
(99, 'Cruisewing', 1, 'Rejuvenating Glow, Moonlit Clouds, Celestial Light', 'Cruisewing.jpg', 'Summon a Cruisewing that restores HP for all current team characters by 1.80% of their Max HPs plus an additional 80 points of HP, up to 4 times. \r\n\r\nCD: 8s'),
(101, 'Diamondclaw', 1, 'Moonlit Clouds, Lingering Tunes', 'Diamondclaw.jpg', 'Transform into Crystal Scorpion and enter a Parry State. Counterattack when the Parry State is over, dealing 48.00%+96 Physical DMG. \r\n\r\nCD: 8s'),
(103, 'Dwarf Cassowary', 1, 'Sierra Gale, Rejuvenating Glow', 'Dwarf_Cassowary.jpg', 'Summon a Dwarf Cassowary that tracks and attacks the enemy, dealing 38.40% Physical DMG 3 time(s). \r\n\r\nCD: 8s'),
(105, 'Electro Predator', 1, 'Molten Rift, Void Thunder', 'Electro_Predator.jpg', 'Summon an Electro Predator to shoot the enemy 5 times. The first 4 shots deals 17.28% Electro DMG, and the last deals 46.08% Electro DMG. \r\n\r\nCD: 8s'),
(106, 'Excarat', 1, 'Freezing Frost, Havoc Eclipse', 'Excarat.jpg', 'Transform into an Excarat and tunnel underground to advance. In this state, you have the ability to change your direction and are immune to damage. \r\n\r\nCD: 8s'),
(108, 'Fission Junrock', 1, 'Moonlit Clouds, Void Thunder, Rejuvenating Glow', 'Fission_Junrock.jpg', 'Summon a Fission Junrock. Generate a Resonance Effect that restores 2% HP for friendly units each time. If not in combat, you can pick up minerals or plants nearby. \r\n\r\nCD: 15s'),
(112, 'Fusion Dreadmane', 1, 'Rejuvenating Glow, Molten Rift', 'Fusion_Dreadmane.jpg', 'Summon a Fusion Dreadmane that fiercely strikes the enemy, dealing 32.00%+64 Fusion DMG. \r\n\r\nCD: 8s'),
(113, 'Fusion Prism', 1, 'Freezing Frost, Lingering Tunes, Molten Rift', 'Fusion_Prism.jpg', 'Summon a Fusion Prism to fire a crystal shard, dealing 32.00%+64 Fusion DMG. \r\n\r\nCD: 8s'),
(114, 'Fusion Warrior', 1, 'Sierra Gale, Void Thunder, Molten Rift', 'Fusion_Warrior.jpg', 'Transform into Fusion Warrior to perform a Counterattack. If the Counterattack is successful, the cooldown time of this skill will be reduced by 70.00%, and 288.00% Fusion DMG will be dealt. \r\n\r\nCD: 15s'),
(118, 'Glacio Predator', 1, 'Celestial Light, Freezing Frost', 'Glacio_Predator.jpg', 'Summon a Glacio Predator that throws an ice spear, dealing 46.08% Glacio DMG on hit. Deal 4.61% Glacio DMG up to 10 times during the charging time, and 23.04% Glacio DMG when the spear explodes. \r\n\r\nCD: 8s'),
(120, 'Glacio Prism', 1, 'Havoc Eclipse, Moonlit Clouds, Freezing Frost', 'Glacio_Prism.jpg', 'Summon a Glacio Prism that continuously fires three crystal shards, each dealing 38.40% Glacio DMG. \r\n\r\nCD: 8s'),
(121, 'Gulpuff', 1, 'Celestial Light, Freezing Frost', 'Gulpuff.jpg', 'Summon a Gulpuff that blows bubbles 5 times, each time dealing 23.04% Glacio DMG. \r\n\r\nCD: 8s'),
(123, 'Havoc Prism', 1, 'Void Thunder, Celestial Light, Havoc Eclipse', 'Havoc_Prism.jpg', 'Summon a Havoc Prism to fire five crystal shards, each dealing 23.04% Havoc DMG. \r\n\r\nCD: 8s'),
(124, 'Havoc Warrior', 1, 'Celestial Light, Havoc Eclipse', 'Havoc_Warrior.jpg', 'Transform into Havoc Warrior to attack up to 3 times, dealing 171.73% Havoc DMG each time. \r\n\r\nCD: 15s'),
(125, 'Hoartoise', 1, 'Celestial Light, Freezing Frost', 'Hoartoise.jpg', 'Transform into Hoartoise and slowly restore HP. Use the Echo skill again to exit the transformation state. \r\n\r\nCD: 8s'),
(127, 'Hooscamp', 1, 'Lingering Tunes, Sierra Gale', 'Hooscamp.jpg', 'Transform into Hooscamp Flinger and pounce at the enemies, dealing 48.00%+96 Aero DMG. \r\n\r\nCD: 8s'),
(130, 'Lava Larva', 1, 'Lingering Tunes, Molten Rift', 'Lava_Larva.jpg', 'Summon a Lava Larva that continuously attacks enemies, dealing 38.40% Fusion DMG with each hit. The Lava Larva disappears when the summoner is switched out or moves too far away. \r\n\r\nCD: 8s'),
(144, 'Sabyr Boar', 1, 'Moonlit Clouds, Sierra Gale, Freezing Frost', 'Sabyr_Boar.jpg', 'Summon a Sabyr Boar to headbutt the enemy into the air, dealing 32.00%+64 Physical DMG. \r\n\r\nCD: 8s'),
(148, 'Snip Snap', 1, 'Lingering Tunes, Rejuvenating Glow, Molten Rift', 'Snip_Snap.jpg', 'Summon a Snip Snap that throws fireballs at the enemy, dealing 32.00%+64 Fusion DMG on-hit. \r\n\r\nCD: 8s\r\n\r\n'),
(150, 'Spectro Prism', 1, 'Molten Rift, Void Thunder, Celestial Light', 'Spectro_Prism.jpg', 'Summon a Spectro Prism to emit a laser that hits the enemy up to 8 times, dealing 14.40% Spectro DMG each time. \r\n\r\nCD: 8s'),
(151, 'Tick Tack', 1, 'Lingering Tunes, Rejuvenating Glow, Havoc Eclipse', 'Tick_Tack.jpg', 'Summon a Tick Tack that charges and bites the enemy. The charge from Tick Tack will deal 68.48% Havoc DMG to the enemy, and the bite will deal 102.72% Havoc DMG to the enemy. Reduces enemy Vibration Strength by up to 5.00% during 5s. \r\n\r\nCD: 15s'),
(152, 'Traffic Illuminator', 1, 'Void Thunder, Sierra Gale, Molten Rift', 'Traffic_Illuminator.jpg', 'Summon a Traffic Illuminator, immobilizing enemies for up to 1s. The immobilization will be lifted once the enemy is hit. \r\n\r\nCD: 15s'),
(154, 'Vanguard Junrock', 1, 'Rejuvenating Glow, Void Thunder, Lingering Tunes', 'Vanguard_Junrock.jpg', 'Summon a Vanguard Junrock that charges forward, dealing 32.00%+64 Physical DMG to enemies in its path. \r\n\r\nCD: 8s'),
(156, 'Whiff Whaff', 1, 'Rejuvenating Glow, Moonlit Clouds, Sierra Gale', 'Whiff_Whaff.jpg', 'Summon a Whiff Whaff that triggers an air explosion, dealing 51.36% Aero DMG and produce a Low-pressure Zone. The Low-pressure Zone continuously pulls enemies nearby towards the center for 2s, dealing 19.97% Aero DMG up to 6 times. \r\n\r\nCD: 15s'),
(157, 'Baby Roseshroom', 1, 'Sierra Gale, Havoc Eclipse', 'Baby_Roseshroom.jpg', 'Summon a Baby Roseshroom that fires a laser, dealing 32.00%+64 Havoc DMG. \r\n\r\nCD: 8s'),
(158, 'Zig Zag', 1, 'Moonlit Clouds, Lingering Tunes, Celestial Light', 'Zig_Zag.jpg', 'Summon a Zig Zag that detonates Spectro energy, dealing 48.00%+96 Spectro DMG and creating a Stagnation Zone that lasts 1.8s. \r\n\r\nCD: 15s'),
(160, 'Dreamless', 4, 'Havoc Eclipse', 'dreamless.jpg', 'Transform into Dreamless and perform 6 consecutive strikes. The first 5 strikes deal 54.08% Havoc DMG each, and the last strike deal 270.40% Havoc DMG. The DMG of this Echo Skill is increased by 50.00% during the first 5s after Rover: Havoc casts Resonance Liberation: Deadening Abyss. \r\n\r\nCD: 20s'),
(161, 'Feilian Beringal', 4, 'Sierra Gale', 'feilian_beringal.jpg', 'Transform into Feilian Beringal to perform a powerful kick. If the kick lands on an enemy, immediately perform a follow-up strike. The kick deals 231.84% Aero DMG, and the follow-up strike deals 283.36% Aero DMG. After the follow-up strike hits, the current character\'s Aero DMG increases by 12.00%, and the Heavy Attack DMG increases by 12.00% for 15s \r\n\r\nCD: 20s'),
(162, 'Impermanence Heron', 4, 'Moonlit Clouds', 'impermanence_heron.jpg', 'Transform into Impermanence Heron to fly up and smack down, dealing 310.56% Havoc DMG. Long press to stay as Impermanence Heron and continuously spit flames, each attack dealing 55.73% Havoc DMG. Once the initial attack lands on any enemy, the current character regains 10 Resonance Energy. If the current character uses their Outro Skill within the next 15s, the next character\'s damage dealt will be boosted by 12% for 15s.\r\n\r\nCD: 20s\r\n\r\n'),
(163, 'Mourning Aix', 4, 'Celestial Light', 'mourning_aix.jpg', 'Transform into Mourning Aix and perform 2 consecutive claw attacks, each attack dealing 157.44% and 236.16% Spectro DMG respectively. After the transformation, increase current character\'s Spectro DMG by 12.00% and Resonance Liberation DMG by 12.00% for 15s.\r\n\r\nCD: 20s'),
(164, 'Crownless', 4, 'Havoc Eclipse', 'crownless.jpg', 'Transform into Crownless and perform up to 4 consecutive attacks. The first 2 attacks deal 134.08% Havoc DMG each, the 3rd attack deals 100.56% Havoc DMG 2 times, and the 4th attack deals 67.04% Havoc DMG 3 times. After the transformation, increase current character\'s Havoc DMG by 12.00% and Resonance Skill DMG by 12.00% for 15s. \r\n\r\nCD: 20s'),
(165, 'Thundering Mephis', 4, 'Void Thunder', 'thundering_mephis.jpg', 'Transform into Nightmare: Thundering Mephis and attack enemies in front, dealing 405.00% Electro DMG. The Resonator with this Echo equipped in their main slot gains 12.00% Electro DMG Bonus and 12.00% Resonance Liberation DMG Bonus. \r\n\r\nCD: 25s.'),
(166, 'Inferno Rider', 4, 'Molten Rift', 'inferno_rider.jpg', 'Transform into the Inferno Rider to launch up to 3 consecutive slashes in a row, each slash dealing 242.40%, 282.80%, and 282.80% Fusion DMG respectively. After the final hit, increase the current Resonator\'s Fusion DMG by 12.00% and Basic Attack DMG by 12.00% for 15s. Long press the Echo Skill to transform into the Inferno Rider and enter Riding Mode. When exiting Riding Mode, deal 282.80% Fusion DMG to enemies in front. \r\n\r\nCD: 20s'),
(171, 'Fallacy of No Return', 4, 'Rejuvenating Glow', 'fallacy_of_no_return.jpg', 'Activate the Echo Skill to summon a fraction of the Fallacy of No Return\'s power and deal a blast to the surrounding area, inflicting Spectro DMG equal to 15.86% of max HP, after which the Resonator gains 10% bonus Energy Regen and all team members 10% bonus ATK for 20s. Hold Echo Skill to unleash a series of flurry assaults at the cost of STA, each dealing Spectro DMG equal to 1.58% of max HP; Release to end the assail in a powerful blow, dealing Spectro DMG equal to 19.82% of max HP. \r\n\r\nCD: 20s'),
(176, 'Lightcrusher', 3, 'Celestial Light', 'lightcrusher.jpg', 'Lunge forward as a Lightcrusher, dealing 135.36% Spectro DMG. Generate 6 Ablucence on hit. Each Ablucence explosion deals 15.04% Spectro DMG. Hold the Echo Skill to stay in the Lightcrusher form, which allows you to leap up and pounce forward in the air for a short distance. \r\n\r\nCD: 15s'),
(177, 'Lumiscale Construct', 3, 'Void Thunder, Freezing Frost', 'lumiscale_construct.jpg', 'Transform into a Lumiscale Construct and enter a Parry Stance. If you are not attacked during the Parry Stance, slash to deal 553.60% Glacio DMG when the stance finishes. If attacked, counterattack instantly, dealing 553.60%+276.80% Glacio DMG. When hit with a Special Skill attack while in the Parry Stance, break the Special Skill and counterattack, dealing 553.60%+276.80% Glacio DMG. \r\n\r\nCD: 15s');

